def is_word_session_disconnect_error(error):
    """?? Word COM ??????"""
    error_str = str(error)
    return any(p in error_str for p in [
        "RPC_E_DISCONNECTED",
        "0x80010108",
        "The object invoked has disconnected from its clients",
        "Server execution failed",
    ])

class WordPdfConverterSession:
    """在同一批量任务中复用 Word 进程，避免每个文档重复启动。"""

    def __init__(self):
        """初始化Word PDF转换会话。"""
        ensure_word_pdf_single_use_mode_loaded()
        self.word = None
        self.before_processes = set()
        self.com_initialized = False
        self.single_use_mode = _WORD_PDF_FORCE_SINGLE_USE.is_set()

    def start(self):
        """启动当前会话。"""
        if self.word:
            return self

        import comtypes
        import comtypes.client

        self.before_processes = {
            proc.pid for proc in psutil.process_iter(['name'])
            if proc.info['name'] == 'WINWORD.EXE'
        }

        print("[PDF转换] 初始化COM库并启动Word...")
        comtypes.CoInitialize()
        self.com_initialized = True

        self.word = comtypes.client.CreateObject('Word.Application')
        if not self.word:
            raise Exception("无法创建Word应用对象")

        self.word.Visible = False
        self.word.DisplayAlerts = False
        return self

    def stop(self):
        """停止当前会话并释放资源。"""
        if self.word:
            try:
                self.word.Quit()
                logging.info("Word应用已关闭")
            except Exception as error:
                if is_word_session_disconnect_error(error):
                    logging.info(f"Word会话已断开，关闭时忽略Quit异常: {str(error)}")
                else:
                    logging.warning(f"关闭Word应用失败: {str(error)}")
            finally:
                self.word = None

        if self.com_initialized:
            try:
                import comtypes
                comtypes.CoUninitialize()
                logging.info("COM库已释放")
            except Exception as error:
                logging.warning(f"释放COM库失败: {str(error)}")
            finally:
                self.com_initialized = False

        try:
            after_processes = [
                proc for proc in psutil.process_iter(['name'])
                if proc.info['name'] == 'WINWORD.EXE' and proc.pid not in self.before_processes
            ]
            for proc in after_processes:
                try:
                    proc.terminate()
                    proc.wait(timeout=2)
                    logging.info(f"已终止Word进程: {proc.pid}")
                except Exception as error:
                    logging.warning(f"终止Word进程失败: {str(error)}")
        except Exception as error:
            logging.warning(f"处理Word进程失败: {str(error)}")

        self.before_processes = set()

    def _convert_once(self, word_path, pdf_path):
        """执行一次Word到PDF转换。"""
        doc = None

        if not self.word:
            self.start()

        print(f"[PDF转换] 开始处理: {word_path.name}")

        if not word_path.exists():
            raise Exception(f"Word文件不存在: {word_path}")

        pdf_path.parent.mkdir(parents=True, exist_ok=True)

        try:
            if not hasattr(self.word, 'Documents') or not self.word.Documents:
                raise Exception("Word应用的Documents对象无效")

            absolute_word_path = str(word_path.absolute())
            print(f"[PDF转换] 打开文档: {word_path.name}")
            doc = self.word.Documents.Open(absolute_word_path)
            if not doc:
                raise Exception("无法打开Word文档")

            if not hasattr(doc, 'SaveAs'):
                raise Exception("文档对象的SaveAs方法无效")

            print(f"[PDF转换] 保存为PDF: {pdf_path.name}")
            doc.SaveAs(str(pdf_path), FileFormat=17)
            print("[PDF转换] ✓ PDF保存成功")
            logging.info(f"PDF保存成功: {pdf_path}")
        finally:
            if doc:
                try:
                    doc.Close()
                    logging.info("文档已关闭")
                except Exception as error:
                    logging.warning(f"关闭文档失败: {str(error)}")

    def convert(self, word_path, pdf_path):
        """执行转换流程。"""
        if self.single_use_mode and self.word:
            self.stop()

        try:
            self._convert_once(word_path, pdf_path)
        except Exception as error:
            if not is_word_session_disconnect_error(error):
                raise

            logging.warning(f"检测到Word会话失效，已重建并重试当前PDF: {str(error)}")
            self.stop()
            self.single_use_mode = True
            _WORD_PDF_FORCE_SINGLE_USE.set()
            persist_word_pdf_single_use_mode()
            self._convert_once(word_path, pdf_path)
        finally:
            if self.single_use_mode:
                self.stop()


@contextmanager
def pdf_conversion_batch():
    """在单次合同批量生成中复用同一个 Word 进程。"""
    active_session = getattr(_WORD_PDF_CONVERTER_LOCAL, 'session', None)
    if active_session is not None:
        yield active_session
        return

    session = WordPdfConverterSession()
    _WORD_PDF_CONVERTER_LOCAL.session = session
    try:
        yield session
    finally:
        try:
            session.stop()
        finally:
            _WORD_PDF_CONVERTER_LOCAL.session = None


@lru_cache(maxsize=64)
def _read_template_bytes(template_path_str, modified_time_ns, file_size):
    """读取模板文件的字节内容。"""
    del modified_time_ns, file_size
    return Path(template_path_str).read_bytes()


def load_docx_template(template_path):
    """按文件状态缓存模板字节，每次返回新的模板实例。"""
    from docxtpl import DocxTemplate

    resolved_path = Path(template_path).resolve()
    stat_result = resolved_path.stat()
    template_bytes = _read_template_bytes(
        str(resolved_path),
        stat_result.st_mtime_ns,
        stat_result.st_size,
    )
    return DocxTemplate(BytesIO(template_bytes))


def _resolve_requests_cert_path():
    """定位 requests 在开发和打包环境下都可用的 CA 证书文件。"""
    candidate_paths = []

    if getattr(sys, 'frozen', False):
        meipass = getattr(sys, '_MEIPASS', '')
        if meipass:
            candidate_paths.append(Path(meipass) / 'certifi' / 'cacert.pem')
            # 在某些 PyInstaller 版本中 certifi 数据可能在根目录
            candidate_paths.append(Path(meipass) / 'cacert.pem')
        candidate_paths.append(APP_ROOT / '_internal' / 'certifi' / 'cacert.pem')
        candidate_paths.append(APP_ROOT / '_internal' / 'cacert.pem')
        candidate_paths.append(APP_ROOT / 'certifi' / 'cacert.pem')
        candidate_paths.append(APP_ROOT / 'cacert.pem')
        # 额外的备选：在 _internal 下递归查找 cacert.pem（部分环境 certifi 路径不同）
        try:
            internal_dir = APP_ROOT / '_internal'
            if internal_dir.exists():
                for found in internal_dir.rglob('cacert.pem'):
                    candidate_paths.append(found)
                    break  # 找到一个就够
        except Exception:
            pass

    # 尝试从 certifi 包本身定位证书文件
    try:
        import certifi as _certifi_module
        if hasattr(_certifi_module, '__file__') and _certifi_module.__file__:
            certifi_dir = Path(_certifi_module.__file__).parent
            candidate_paths.append(certifi_dir / 'cacert.pem')
    except Exception:
        pass

    for env_name in ('REQUESTS_CA_BUNDLE', 'SSL_CERT_FILE'):
        env_value = os.environ.get(env_name, '').strip()
        if env_value:
            candidate_paths.append(Path(env_value))

    try:
        candidate_paths.append(Path(certifi.where()))
    except Exception:
        pass

    for candidate in candidate_paths:
        try:
            resolved_candidate = Path(candidate).resolve()
        except Exception:
            resolved_candidate = Path(candidate)
        if _is_valid_ca_bundle_path(resolved_candidate):
            return resolved_candidate
    return None


def _is_valid_ca_bundle_path(cert_path):
    """Return True only for a readable PEM CA bundle."""
    if not cert_path:
        return False
    try:
        path = Path(cert_path)
        if not path.exists() or not path.is_file() or path.stat().st_size < 1024:
            return False
        return b'-----BEGIN CERTIFICATE-----' in path.read_bytes()
    except Exception:
        return False


def _materialize_requests_cert_path(cert_path):
    """将 CA 证书复制到本地稳定路径，避免部分机器无法直接读取打包目录中的证书。"""
    if _is_valid_ca_bundle_path(cert_path):
        return Path(cert_path)

    try:
        cache_dir = Path(tempfile.gettempdir()) / 'Project_zjt' / 'certifi'
        cache_dir.mkdir(parents=True, exist_ok=True)
        materialized_path = cache_dir / 'cacert.pem'

        bundle_bytes = None
        try:
            bundle_bytes = pkgutil.get_data('certifi', 'cacert.pem')
        except Exception:
            bundle_bytes = None

        if bundle_bytes:
            existing_bytes = None
            if materialized_path.exists():
                try:
                    existing_bytes = materialized_path.read_bytes()
                except Exception:
                    existing_bytes = None
            if existing_bytes != bundle_bytes:
                materialized_path.write_bytes(bundle_bytes)
        else:
            if not cert_path:
                return None

            source_path = Path(cert_path)
            if not _is_valid_ca_bundle_path(source_path):
                return None

            if not getattr(sys, 'frozen', False):
                return source_path

            if (not materialized_path.exists()) or source_path.stat().st_size != materialized_path.stat().st_size:
                shutil.copy2(source_path, materialized_path)

        if _is_valid_ca_bundle_path(materialized_path):
            return materialized_path
    except Exception:
        if cert_path:
            source_path = Path(cert_path)
            if _is_valid_ca_bundle_path(source_path):
                return source_path
        return None

    if cert_path:
        source_path = Path(cert_path)
        if _is_valid_ca_bundle_path(source_path):
            return source_path
    return None


def _load_requests_cert_bundle_bytes(cert_path=None):
    """优先从 certifi 包内容读取证书字节，失败时再回退到文件读取。"""
    try:
        bundle_bytes = pkgutil.get_data('certifi', 'cacert.pem')
        if bundle_bytes:
            return bundle_bytes
    except Exception:
        pass

    # 回退：使用 certifi.contents() 获取内置证书字符串
    try:
        contents = certifi.contents()
        if contents:
            return contents.encode('ascii')
    except Exception:
        pass

    return None


def _build_requests_ssl_context(cert_path=None):
    """构建基于内存 CA 证书的 SSLContext，避免依赖目标机文件路径。"""
    bundle_bytes = _load_requests_cert_bundle_bytes(cert_path)
    if bundle_bytes:
        try:
            ssl_context = ssl.create_default_context()
            ssl_context.load_verify_locations(cadata=bundle_bytes.decode('ascii'))
            return ssl_context, 'certifi:cadata'
        except Exception:
            pass

    if cert_path:
        try:
            ssl_context = ssl.create_default_context(cafile=str(cert_path))
            return ssl_context, str(cert_path)
        except Exception:
            pass

    try:
        fallback_path = certifi.where()
        ssl_context = ssl.create_default_context(cafile=fallback_path)
        return ssl_context, fallback_path
    except Exception:
        return None, None


class SSLContextAdapter(HTTPAdapter):
    """携带自定义SSL上下文的请求适配器。"""
    def __init__(self, ssl_context=None, *args, **kwargs):
        """初始化SSL上下文适配器。"""
        self._ssl_context = ssl_context
        super().__init__(*args, **kwargs)

    def init_poolmanager(self, connections, maxsize, block=False, **pool_kwargs):
        """处理initpoolmanager逻辑。"""
        if self._ssl_context is not None:
            pool_kwargs['ssl_context'] = self._ssl_context
        return super().init_poolmanager(connections, maxsize, block=block, **pool_kwargs)

    def proxy_manager_for(self, proxy, **proxy_kwargs):
        """处理proxymanagerfor逻辑。"""
        if self._ssl_context is not None:
            proxy_kwargs['ssl_context'] = self._ssl_context
        return super().proxy_manager_for(proxy, **proxy_kwargs)

    def cert_verify(self, conn, url, verify, cert):
        """Use the preloaded SSLContext instead of asking requests to reload CA files."""
        if self._ssl_context is not None:
            if cert:
                if isinstance(cert, tuple):
                    conn.cert_file, conn.key_file = cert
                else:
                    conn.cert_file = cert
            return
        return super().cert_verify(conn, url, verify, cert)


def _build_requests_session():
    """构建 requests 会话 — 不使用自定义 SSLContext，由 verify 参数控制。"""
    session = requests.Session()
    session.trust_env = False
    return session


# ── 证书定位：3.4.8 彻底修复 X509: NO_CERTIFICATE_OR_CRL_FOUND ──────────────────────────
# 根因：PyInstaller 打包后 certifi.where() 返回 PYZ 内部路径（文件系统不存在），
#        certifi.contents()/pkgutil.get_data() 也可能失败，
#        导致 OpenSSL 找不到任何 CA 证书。
# 方案（按优先级）：
# 1. 从 certifi 内存/cacert.pem 文件读取 PEM 数据 → SSLContext.load_verify_locations(cadata=)
# 2. 从磁盘找到有效 cacert.pem → SSLContext.load_verify_locations(cafile=)
# 3. ssl.create_default_context() → Windows 系统证书存储
# 4. 将 PEM 数据写入临时文件 → verify=文件路径
# 最终保证 REQUESTS_SSL_CONTEXT 一定不为 None

def _read_certifi_cadata_bytes():
    """从 certifi 包获取 CA 证书 PEM 字节，尝试所有可能的方式。"""
    try:
        contents = certifi.contents()
        if contents and isinstance(contents, str) and '-----BEGIN CERTIFICATE-----' in contents:
            return contents.encode('ascii')
    except Exception:
        pass
    try:
        bundle_bytes = pkgutil.get_data('certifi', 'cacert.pem')
        if bundle_bytes and b'-----BEGIN CERTIFICATE-----' in bundle_bytes:
            return bundle_bytes
    except Exception:
        pass
    return None


def _is_pem_content_valid(cert_path):
    if not cert_path:
        return False
    try:
        path = Path(cert_path)
        if not path.exists() or not path.is_file() or path.stat().st_size < 1024:
            return False
        content = path.read_bytes()
        return b'-----BEGIN CERTIFICATE-----' in content
    except Exception:
        return False


def _find_cert_file_on_disk():
    """在打包后的所有可能路径中查找 cacert.pem 文件。"""
    candidates = []
    if getattr(sys, 'frozen', False):
        meipass = getattr(sys, '_MEIPASS', '')
        if meipass:
            candidates += [
                Path(meipass) / 'certifi' / 'cacert.pem',
                Path(meipass) / 'cacert.pem',
            ]
        candidates += [
            APP_ROOT / '_internal' / 'certifi' / 'cacert.pem',
            APP_ROOT / '_internal' / 'cacert.pem',
            APP_ROOT / 'certifi' / 'cacert.pem',
            APP_ROOT / 'cacert.pem',
        ]
        try:
            internal = APP_ROOT / '_internal'
            if internal.exists():
                for found in internal.rglob('cacert.pem'):
                    candidates.append(found)
        except Exception:
            pass
    try:
        candidates.append(Path(certifi.__file__).parent / 'cacert.pem')
    except Exception:
        pass
    try:
        candidates.append(Path(certifi.where()))
    except Exception:
        pass
    for p in candidates:
        try:
            if _is_pem_content_valid(p):
                return p
        except Exception:
            continue
    return None


def _read_cert_bytes_from_file(cert_path):
    """从磁盘文件读取 PEM 证书字节。"""
    try:
        data = Path(cert_path).read_bytes()
        if data and b'-----BEGIN CERTIFICATE-----' in data:
            return data
    except Exception:
        pass
    return None


def _write_cert_to_tempfile(cert_bytes):
    """将证书字节写入临时文件，返回文件路径。"""
    try:
        cache_dir = Path(tempfile.gettempdir()) / 'Project_zjt' / 'certifi'
        cache_dir.mkdir(parents=True, exist_ok=True)
        temp_pem = cache_dir / 'cacert.pem'
        existing = None
        if temp_pem.exists():
            try:
                existing = temp_pem.read_bytes()
            except Exception:
                existing = None
        if existing != cert_bytes:
            temp_pem.write_bytes(cert_bytes)
        if _is_pem_content_valid(temp_pem):
            return temp_pem
    except Exception:
        pass
    return None


def _build_ssl_context():
    """构建可用的 SSLContext，按优先级尝试所有证书来源。
    返回 (ssl_context, cert_source_desc) 或 (None, None)。"""
    # 策略1: 从 certifi 内存获取 PEM 数据
    cadata = _read_certifi_cadata_bytes()
    if cadata:
        try:
            ctx = ssl.create_default_context()
            ctx.load_verify_locations(cadata=cadata.decode('ascii', errors='replace'))
            return ctx, 'certifi:cadata'
        except Exception:
            pass

    # 策略2: 从磁盘找到 cacert.pem 文件，用 cafile 加载
    cert_file = _find_cert_file_on_disk()
    if cert_file:
        try:
            ctx = ssl.create_default_context()
            ctx.load_verify_locations(cafile=str(cert_file))
            return ctx, f'file:{cert_file}'
        except Exception:
            pass
        # cafile 失败，尝试读取文件内容用 cadata
        file_bytes = _read_cert_bytes_from_file(cert_file)
        if file_bytes:
            try:
                ctx = ssl.create_default_context()
                ctx.load_verify_locations(cadata=file_bytes.decode('ascii', errors='replace'))
                return ctx, f'file_cadata:{cert_file}'
            except Exception:
                pass

    # 策略3: ssl.create_default_context() 使用 Windows 系统证书存储
    try:
        ctx = ssl.create_default_context()
        return ctx, 'system_default'
    except Exception:
        pass

    return None, None


def _build_fallback_cert_file():
    """所有 SSLContext 方案失败时，尝试将证书写入临时文件供 verify 参数使用。"""
    cadata = _read_certifi_cadata_bytes()
    if cadata:
        result = _write_cert_to_tempfile(cadata)
        if result:
            return result
    cert_file = _find_cert_file_on_disk()
    if cert_file:
        file_bytes = _read_cert_bytes_from_file(cert_file)
        if file_bytes:
            result = _write_cert_to_tempfile(file_bytes)
            if result:
                return result
    return None


REQUESTS_SSL_CONTEXT, _CERT_SOURCE = _build_ssl_context()
REQUESTS_CERT_PATH = None

if REQUESTS_SSL_CONTEXT is None:
    REQUESTS_CERT_PATH = _build_fallback_cert_file()


def _build_requests_session_with_sslcontext():
    session = requests.Session()
    session.trust_env = False
    if REQUESTS_SSL_CONTEXT:
        adapter = SSLContextAdapter(ssl_context=REQUESTS_SSL_CONTEXT)
        session.mount('https://', adapter)
        session.mount('http://', adapter)
    return session


if REQUESTS_SSL_CONTEXT:
    REQUESTS_VERIFY = True
    _REQUESTS_SESSION_FACTORY = _build_requests_session_with_sslcontext
elif REQUESTS_CERT_PATH:
    REQUESTS_VERIFY = str(REQUESTS_CERT_PATH)
    os.environ['REQUESTS_CA_BUNDLE'] = str(REQUESTS_CERT_PATH)
    os.environ['SSL_CERT_FILE'] = str(REQUESTS_CERT_PATH)
    os.environ['CURL_CA_BUNDLE'] = str(REQUESTS_CERT_PATH)
    _REQUESTS_SESSION_FACTORY = _build_requests_session
else:
    REQUESTS_VERIFY = True
    _REQUESTS_SESSION_FACTORY = _build_requests_session

# 线程本地 Session + 全局锁：每个线程持有独立的 requests.Session，
# 但所有 HTTP 请求必须通过全局锁串行化，彻底避免 WININET.dll 并发访问冲突。
_THREAD_LOCAL_SESSIONS = threading.local()
_REQUESTS_LOCK = threading.Lock()

def _get_thread_local_session():
    """返回当前线程的独立 requests.Session（线程安全）。"""
    s = getattr(_THREAD_LOCAL_SESSIONS, 'session', None)
    if s is None:
        s = _REQUESTS_SESSION_FACTORY()
        _THREAD_LOCAL_SESSIONS.session = s
    return s


def get_requests_kwargs(timeout=60, **kwargs):
    """统一 requests 参数，确保打包后 HTTPS 仍使用有效 CA 证书。"""
    request_kwargs = dict(kwargs)
    request_kwargs.setdefault('timeout', timeout)
    request_kwargs.setdefault('verify', REQUESTS_VERIFY)
    return request_kwargs


def perform_requests_request(method, url, **kwargs):
    """发起 HTTPS 请求，verify 参数指向 cacert.pem 文件。

    所有 HTTP 请求通过全局锁串行化，防止多个线程同时访问 WININET.dll 导致内存访问冲突。
    """
    request_kwargs = dict(kwargs)
    timeout = request_kwargs.pop('timeout', 30)
    request_kwargs = get_requests_kwargs(timeout=timeout, **request_kwargs)
    with _REQUESTS_LOCK:
        return _get_thread_local_session().request(method, url, **request_kwargs)


def resolve_app_path(path_value):
    """将相对路径解析到程序根目录，绝对路径保持不变（若盘符不存在则回退到程序根目录）"""
    if not path_value:
        return APP_ROOT
    path = Path(path_value)
    if path.is_absolute():
        # 验证盘符是否可访问（项目迁移到其他盘符时自动回退）
        drive_root = str(path.drive) + '\\'
        if os.path.exists(drive_root):
            return path
        # 盘符不存在，回退到程序根目录
        return APP_ROOT

    if getattr(sys, 'frozen', False):
        resource_candidate = RESOURCE_ROOT / path
        if resource_candidate.exists():
            return resource_candidate

    return APP_ROOT / path


def resolve_existing_app_path(path_value, fallback_path=None):
    """优先返回存在的配置路径，不存在时回退到程序目录内的默认路径"""
    if path_value:
        candidate = resolve_app_path(path_value)
        if candidate.exists():
            return candidate

        if getattr(sys, 'frozen', False):
            legacy_candidate = APP_ROOT / Path(path_value)
            if legacy_candidate.exists():
                return legacy_candidate

    if fallback_path is None:
        return resolve_app_path(path_value) if path_value else None

    fallback = fallback_path if isinstance(fallback_path, Path) else Path(fallback_path)
    return fallback if fallback.is_absolute() else APP_ROOT / fallback


CONFIG_DIR_NAME = '.config'
RESOURCE_DIR_NAME = 'Resources'
