def get_common_config_path(for_save=False):
    """获取系统配置文件路径（从个人配置中读取，直接读文件避免递归）。"""
    configured_path = ''
    config_file = get_config_path(for_save=False)
    if config_file.exists():
        try:
            with open(config_file, 'r', encoding='utf-8') as f:
                user_data = json.load(f)
            if isinstance(user_data, dict):
                configured_path = str(user_data.get('app_settings', {}).get('common_config_path', '') or '').strip()
        except Exception:
            pass

    if configured_path:
        # 验证配置路径的盘符是否可访问（项目迁移到其他盘符时自动回退）
        configured_file = Path(configured_path)
        if configured_file.is_absolute():
            drive_root = str(configured_file.drive) + '\\'
            if not os.path.exists(drive_root):
                # 盘符不存在，回退到程序所在盘符的默认路径
                config_file = CONFIG_DIR / SHARED_SETTINGS_FILENAME
            else:
                config_file = resolve_app_path(configured_path)
        else:
            config_file = resolve_app_path(configured_path)
    else:
        config_file = CONFIG_DIR / SHARED_SETTINGS_FILENAME

    if for_save:
        config_file.parent.mkdir(parents=True, exist_ok=True)
    return config_file


def save_common_config_path(path_value):
    """保存系统配置文件路径到个人配置（仅写个人配置，不覆盖新系统配置文件）。"""
    global _config_cache, _config_last_modified, _common_config_last_modified, _common_config_resolved_path, _current_config_path

    normalized_path = str(path_value or '').strip()
    target_path = normalized_path or SHARED_SETTINGS_FILENAME

    # 只写入个人配置文件，不触发 save_config（避免将当前内存中的共享数据
    # 写回到新指定的系统配置文件，导致新文件的原始数据被旧数据覆盖）。
    config_file = get_config_path(for_save=True)
    config_file.parent.mkdir(parents=True, exist_ok=True)
    personal_config = {}
    if config_file.exists():
        try:
            with open(config_file, 'r', encoding='utf-8') as f:
                personal_config = json.load(f)
        except Exception:
            personal_config = {}
    if not isinstance(personal_config, dict):
        personal_config = {}
    personal_config.setdefault('app_settings', {})['common_config_path'] = target_path
    with open(config_file, 'w', encoding='utf-8') as f:
        json.dump(personal_config, f, ensure_ascii=False, indent=2)

    # 清空全局缓存，下次 load_config() 将从新路径重读系统配置文件
    _config_cache = None
    _config_last_modified = 0
    _common_config_last_modified = 0
    _common_config_resolved_path = None
    _current_config_path = None


def get_common_config_display_path():
    """返回系统配置文件在界面中显示的路径。"""
    config_file = get_config_path(for_save=False)
    if config_file.exists():
        try:
            with open(config_file, 'r', encoding='utf-8') as f:
                user_data = json.load(f)
            if isinstance(user_data, dict):
                configured_path = str(user_data.get('app_settings', {}).get('common_config_path', '') or '').strip()
                if configured_path:
                    return configured_path
        except Exception:
            pass
    return str(get_common_config_path())


def load_common_config():
    """加载系统配置文件。"""
    config_file = get_common_config_path()
    if not config_file.exists():
        return {}
    try:
        with open(config_file, 'r', encoding='utf-8') as f:
            data = json.load(f)
            return data if isinstance(data, dict) else {}
    except Exception as e:
        logging.error(f"加载系统配置文件失败: {str(e)}")
        return {}


def _merge_common_config_sections(base_config, common_config):
    """将系统配置中声明为共享的字段覆盖到运行时配置中。

    系统配置是共享字段的唯一数据源：系统配置中有则用系统配置的值，
    系统配置中没有则清空（不保留个人配置中的旧值）。
    """
    merged_config = copy.deepcopy(base_config if isinstance(base_config, dict) else {})
    if not isinstance(common_config, dict):
        common_config = {}

    # 系统配置文件为空/加载失败时，保留当前内存中的共享字段，不做清空
    if not common_config:
        return merged_config

    for section_name, key_names in COMMON_CONFIG_RULES.items():
        common_section = common_config.get(section_name, {})
        if not isinstance(common_section, dict):
            common_section = {}

        target_section = merged_config.get(section_name)
        if not isinstance(target_section, dict):
            target_section = {}
            merged_config[section_name] = target_section

        for key_name in key_names:
            # 系统配置文件中有则用，没有则设空（以系统配置为准）
            if key_name in common_section:
                target_section[key_name] = copy.deepcopy(common_section[key_name])
            else:
                target_section.pop(key_name, None)

    return merged_config


def split_config_by_scope(config):
    """将配置拆分为个人配置和系统配置。"""
    source_config = config if isinstance(config, dict) else {}
    personal_config = copy.deepcopy(source_config)
    common_config = {}

    # 先抽取共享字段，再从个人配置中剔除相同键，保证两份配置文件职责分离。
    for section_name, key_names in COMMON_CONFIG_RULES.items():
        source_section = source_config.get(section_name, {})
        if isinstance(source_section, dict):
            common_section = {}
            for key_name in key_names:
                if key_name in source_section:
                    common_section[key_name] = copy.deepcopy(source_section[key_name])
            if common_section:
                common_config[section_name] = common_section

        personal_section = personal_config.get(section_name)
        if isinstance(personal_section, dict):
            for key_name in key_names:
                personal_section.pop(key_name, None)
            if not personal_section:
                personal_config.pop(section_name, None)

    return personal_config, common_config


def _save_config_to_targets(config):
    """分别保存个人配置和系统配置。"""
    global _config_cache, _config_last_modified, _common_config_last_modified, _common_config_resolved_path, _current_config_path

    personal_config, common_config = split_config_by_scope(config)
    config_file = get_config_path(for_save=True)
    common_config_file = get_common_config_path(for_save=True)

    config_file.parent.mkdir(parents=True, exist_ok=True)
    with open(config_file, 'w', encoding='utf-8') as f:
        json.dump(personal_config, f, ensure_ascii=False, indent=2)

    if common_config:
        common_config_file.parent.mkdir(parents=True, exist_ok=True)
        with open(common_config_file, 'w', encoding='utf-8') as f:
            json.dump(common_config, f, ensure_ascii=False, indent=2)

    # 保存完成后清空缓存，下次读取时重新从磁盘合并，避免继续使用旧配置。
    _config_cache = None
    _config_last_modified = 0
    _common_config_last_modified = 0
    _common_config_resolved_path = None
    _current_config_path = None


def ensure_personal_config_file():
    """若当前用户缺少个人配置，则基于默认配置生成一份。"""
    config_path = get_config_path(for_save=True)
    seed_config_path = get_personal_profile_seed_path()

    if config_path.exists():
        return config_path, False

    if config_path == seed_config_path:
        return config_path, False

    if not seed_config_path.exists():
        raise FileNotFoundError(f"默认配置文件不存在: {seed_config_path}")

    with open(seed_config_path, 'r', encoding='utf-8') as f:
        default_config = json.load(f)

    config_path.parent.mkdir(parents=True, exist_ok=True)
    with open(config_path, 'w', encoding='utf-8') as f:
        json.dump(default_config, f, ensure_ascii=False, indent=2)

    global _config_cache, _config_last_modified, _current_config_path
    _config_cache = None
    _config_last_modified = 0
    _current_config_path = None
    return config_path, True

