NOISY_RUNTIME_PRINT_PREFIXES = (
    "[DEBUG-",
    "[CRM全选]",
    "[CRM表格列对齐检查]",
    "[PDF转换]",
    "[启动]",
)

NOISY_RUNTIME_PRINT_MESSAGES = {
    "开始处理PDF文件",
    "开始处理Word文件",
    "不保留Word文件，跳过Word文件处理",
}

NOISY_RUNTIME_PRINT_UI_ONLY_PREFIXES = (
    "[operation]",
    "[root] INFO",
    "✓",
    "[RuntimeState]",
    "[DEBUG-",
    "[列宽恢复]",
)


def _should_suppress_runtime_print(message):
    """判断是否需要抑制运行时输出。
    返回值：
        True - 完全抑制（无论UI还是日志文件）
        'ui_only' - 仅抑制UI输出，但仍写日志文件
        False - 不抑制
    """
    text = str(message).strip()
    if not text:
        return False
    if any(text.startswith(prefix) for prefix in NOISY_RUNTIME_PRINT_UI_ONLY_PREFIXES):
        return 'ui_only'
    if any(text.startswith(prefix) for prefix in NOISY_RUNTIME_PRINT_PREFIXES):
        return True
    if text in NOISY_RUNTIME_PRINT_MESSAGES:
        return True
    if text in {'=' * 50, '=' * 80, '-' * 80}:
        return True
    return False



# 保存原始内置 print 引用，用于统配版内部调用
_original_print = builtins.print

def print(*args, **kwargs):
    """包装内置print以统一运行时日志输出。"""
    message = ' '.join(str(arg) for arg in args)
    suppress_result = _should_suppress_runtime_print(message)
    if suppress_result == True:
        return
    if suppress_result == 'ui_only':
        # 仅抑制UI窗口输出，但仍写日志文件
        return _original_print(*args, **kwargs)
    # 同时输出到界面运行窗口
    try:
        import sys
        main_mod = sys.modules.get('__main__')
        if main_mod:
            mf = getattr(main_mod, 'MainFrame', None)
            if mf and hasattr(mf, 'instance') and mf.instance:
                mf.instance.append_output(message)
    except Exception:
        pass
    return _original_print(*args, **kwargs)

# 替换全局 builtins.print，让所有模块都经过此过滤器
builtins.print = print



class ImportantOperationLogFilter(logging.Filter):
    """筛选重要操作日志的过滤器。"""
    EXCLUDED_PATTERNS = (
        "启动时间:",
        "配置文件:",
        "主窗口大小:",
        "设置窗口大小:",
        "窗口大小:",
        "导航栏",
        "检查用户登录状态",
        "验证用户密码",
        "加载UI模块",
        "PyQt6模块导入成功",
        "初始化主窗口",
        "主窗口创建成功",
        "主窗口已显示",
        "--- 程序启动完成，进入主循环 ---",
        "打开CRM字段设置对话框",
        "打开文件生成字段设置对话框",
        "[启动]",
        "窗口居中",
        "[RuntimeState] ✝️ 写入",
        "[RuntimeState] ✅ 写入成功",
        "[RuntimeState] ❌ 写入失败",
        "[RuntimeState]",
        "[DEBUG-",
        "[列宽恢复]",
        "[列宽调整]",
        "[列宽]",
        "系统托盘图标",
        "配置已保存",
    )

    def filter(self, record):
        """决定是否保留当前日志记录。"""
        message = record.getMessage()
        return not any(pattern in message for pattern in self.EXCLUDED_PATTERNS)


