def setup_logging():
    """设置统一日志文件（按日期记录关键操作和异常，过滤调试噪音）"""
    log_dir = Path('log')
    try:
        base_dir = Path(__file__).parent if '__file__' in dir() else Path.cwd()
    except NameError:
        base_dir = Path.cwd()
    log_dir = (base_dir / log_dir).resolve()
    log_dir.mkdir(parents=True, exist_ok=True)

    today = datetime.now().strftime('%Y-%m-%d')
    log_file = log_dir / f'operation_{today}.txt'

    # 清除已有 handler，确保 basicConfig 生效
    root = logging.getLogger()
    for h in list(root.handlers):
        root.removeHandler(h)

    # 文件 handler（INFO+ 写日志文件，过滤 [DEBUG-...] 噪音）
    class _OperationFilter(logging.Filter):
        """只放行 WARNING+ 或不含 [DEBUG- 前缀的 INFO 消息"""
        def filter(self, record: logging.LogRecord) -> bool:
            if record.levelno >= logging.WARNING:
                return True
            msg = record.getMessage()
            if '[DEBUG-' in msg or msg.strip().startswith('[DEBUG'):
                return False
            return True

    fh = logging.FileHandler(log_file, encoding='utf-8')
    fh.setLevel(logging.INFO)
    fh.setFormatter(logging.Formatter('%(asctime)s - %(message)s'))
    fh.addFilter(_OperationFilter())
    root.addHandler(fh)
    # 控制台 handler 必须绑定真实 stderr，避免与 _StderrLogWriter 形成递归
    _real_stderr = getattr(sys.stderr, '_orig', sys.stderr) or sys.__stderr__
    if _real_stderr is not None:
        ch = logging.StreamHandler(_real_stderr)
        ch.setLevel(logging.ERROR)
        ch.setFormatter(logging.Formatter('%(levelname)s: %(message)s'))
        root.addHandler(ch)
    root.setLevel(logging.INFO)
    configure_third_party_loggers()

    # 重定向 stdout 到日志文件，stderr 同时写日志+控制台
    class _StdoutLogWriter:
        _in_write = False
        def write(self, text):
            if self._in_write:
                return
            text = text.strip()
            if text:
                self._in_write = True
                try:
                    logging.info(text)
                finally:
                    self._in_write = False
        def flush(self): pass

    class _StderrLogWriter:
        def __init__(self, original_stderr):
            self._orig = original_stderr
        _in_write = False
        def write(self, text):
            if self._in_write:
                if self._orig is not None:
                    self._orig.write(text)
                return
            stripped = text.strip()
            if stripped:
                self._in_write = True
                try:
                    logging.error(stripped)
                finally:
                    self._in_write = False
            if self._orig is not None:
                self._orig.write(text)
        def flush(self):
            if self._orig is not None:
                self._orig.flush()

    if not isinstance(sys.stdout, _StdoutLogWriter):
        sys.stdout = _StdoutLogWriter()
    if not hasattr(sys.stderr, '_orig'):
        sys.stderr = _StderrLogWriter(_real_stderr)

    # 修正 root logger 中指向旧 stderr 的 StreamHandler，避免日志消息
    # 经由 _StderrLogWriter 被重复输出并错误地标记为 ERROR 级别
    for handler in list(root.handlers):
        if isinstance(handler, logging.StreamHandler) and not isinstance(handler, logging.FileHandler):
            try:
                if handler.stream is not _real_stderr:
                    handler.setStream(_real_stderr)
            except AttributeError:
                # 部分 Python 版本的 StreamHandler 无 setStream，直接替换 stream 属性
                if getattr(handler, 'stream', None) is not _real_stderr:
                    handler.stream = _real_stderr

    # 全局异常捕获
    def _log_exception(exc_type, exc_value, exc_tb):
        import traceback
        msg = ''.join(traceback.format_exception(exc_type, exc_value, exc_tb))
        logging.critical(f"未捕获异常:\n{msg}")
    sys.excepthook = _log_exception


def setup_operation_logger():
    """返回统一的日志记录器（与 root logger 共用同一个文件）"""
    return logging.getLogger('operation')


# 创建全局操作日志实例
operation_log = setup_operation_logger()


