    def switch_to_page(self, index):
        """切换到指定页面"""
        # 权限检查：普通用户不能访问管理员页面
        is_admin_user = (user_type == "admin" or current_user in ("Zengjiataoadmin", "001"))
        restricted_pages = {2, 5, 7}  # 自定义报表、对象查询、部门员工（仅管理员）
        if index in restricted_pages and not is_admin_user:
            return

        flush_pending_config()

        # ✅【2026-06-18 修复】页面名称列表与 content_stack 创建顺序一致
        page_names = ["文件生成", "订单转合同", "自定义报表", "文件移动", "招投标授权", "对象查询", "设置", "部门员工"]
        page_name = page_names[index] if index < len(page_names) else f"页面{index}"

        if index == 6:  # 设置页面
            if getattr(self, 'output_visible', False):
                self.on_toggle_output()
                self.output_auto_hidden_by_settings = True
            # ✅ 每次切换到设置页面时，刷新当前对象的加载条数等设置（确保与对象查询页面一致）
            if hasattr(self, 'settings_dialog'):
                dlg = self.settings_dialog
                api_name = dlg._get_current_settings_api_name()
                if api_name and hasattr(dlg, '_load_obj_query_settings'):
                    dlg._load_obj_query_settings(api_name)
        elif getattr(self, 'output_auto_hidden_by_settings', False):
            if not getattr(self, 'output_visible', True):
                self.on_toggle_output()
            self.output_auto_hidden_by_settings = False

        # ✅【2026-06-18 修复】CRM订单首次自动加载
        if index == 1:  # CRM订单页面
            if not getattr(self, '_crm_first_load_completed', False):
                print(f"\n[DEBUG-CRM] 🎯 首次进入CRM订单页面，自动加载数据...")
                self._crm_first_load_completed = True
                from PyQt6.QtCore import QTimer
                QTimer.singleShot(100, self._crm_first_auto_load)

        # ✅【2026-06-18 修复】招投标授权（商机）首次自动加载 — index=5（pdf_watermark 页面）
        if index == 4:  # 招投标授权页面
            if not getattr(self, '_opportunity_first_load_completed', False):
                print(f"\n[DEBUG-商机] 🎯 首次进入招投标授权页面，自动加载商机数据...")
                self._opportunity_first_load_completed = True
                from PyQt6.QtCore import QTimer
                QTimer.singleShot(200, self._opportunity_first_auto_load)

        # ✅【2026-05-12 修复】对象查询首次自动加载检测 — index=6（dashboard 移除后偏移）
        if index == 5:  # 对象查询页面
            if not getattr(self, '_obj_query_first_auto_load_done', False):
                print(f"\n[DEBUG-对象查询] 🎯 首次进入对象查询页面，准备自动加载数据...")
                self._obj_query_first_auto_load_done = True

                # 检查是否有默认对象配置
                fx_cfg = getattr(self, 'config', {}).get('fxiaoke', {})
                default_obj_api = fx_cfg.get('default_obj_query_object', '')

                # ✅【关键修复】如果无默认对象配置，使用第一个有效对象
                if not default_obj_api:
                    print(f"[DEBUG-对象查询] ℹ️ 未配置默认对象，尝试使用第一个有效对象")
                    for i in range(1, self.obj_query_object_combo.count()):  # 跳过索引0（"请选择对象"）
                        first_api = self.obj_query_object_combo.itemData(i)
                        if first_api:
                            default_obj_api = first_api
                            print(f"[DEBUG-对象查询] ✅ 使用第一个对象: '{default_obj_api}' ({self.obj_query_object_combo.itemText(i)})")
                            break

                if default_obj_api:
                    # 有默认对象 → 延迟自动加载（确保UI完全渲染）
                    from PyQt6.QtCore import QTimer

                    def _auto_load_default_obj():
                        """延迟加载默认对象数据"""
                        print(f"[DEBUG-对象查询] 🚀 自动加载默认对象 | API: '{default_obj_api}'")

                        # 检查当前选择的对象是否是默认对象
                        current_api = self.obj_query_object_combo.currentData() or ''

                        if current_api != default_obj_api:
                            # 当前选中的不是默认对象 → 切换到默认对象（会触发_on_obj_query_object_changed）
                            for i in range(self.obj_query_object_combo.count()):
                                if self.obj_query_object_combo.itemData(i) == default_obj_api:
                                    self.obj_query_object_combo.setCurrentIndex(i)
                                    break
                        else:
                            # 已经选中默认对象 → 带筛选条件加载
                            self._pending_obj_query_api = default_obj_api
                            self._do_obj_query_load(default_obj_api)

                    # 延迟200ms确保UI完全就绪
                    QTimer.singleShot(200, _auto_load_default_obj)
                else:
                    # 无可用对象 → 提示用户
                    print(f"[DEBUG-对象查询] ⚠️ 无可用的业务对象")
                    if hasattr(self, 'obj_query_status_label'):
                        self.obj_query_status_label.setText("⚠️ 请先在设置中添加业务对象")

            # ✅ 每次切换到对象查询页面时，从配置同步加载条数（确保与设置页面一致）
            self._sync_load_count_spin_from_config()
            # ✅【新增】每次切换到对象查询页面时，同步加载快捷筛选条件
            if hasattr(self, 'obj_query_object_combo'):
                current_api = self.obj_query_object_combo.currentData() or ''
                if current_api:
                    self._load_quick_filters_for_object(current_api)

        # ✅ 部门员工页面首次自动加载检测
        if index == 8:  # 部门员工页面
            if not getattr(self, '_usergroup_first_load_done', False):
                print(f"\n[DEBUG-部门员工] 🎯 首次进入部门员工页面，自动加载数据...")
                self._usergroup_first_load_done = True
                from PyQt6.QtCore import QTimer
                QTimer.singleShot(200, self._usergroup_fetch_data)

        if hasattr(self, 'content_stack'):
            self.setUpdatesEnabled(False)
            self.content_stack.setCurrentIndex(index)
            self.setUpdatesEnabled(True)
            # 切换到自定义报表时刷新列表 + 编辑器数据源
            if index == 2:
                if hasattr(self, 'custom_report_list_page'):
                    try:
                        self.custom_report_list_page.refresh()
                    except Exception:
                        pass
                # 同时刷新编辑器数据源选项（MySQL 配置变更后无需重启）
                if hasattr(self, '_refresh_custom_report_main_source_options'):
                    try:
                        self._refresh_custom_report_main_source_options()
                    except Exception:
                        pass
                if hasattr(self, '_refresh_custom_report_field_source_options'):
                    try:
                        self._refresh_custom_report_field_source_options()
                    except Exception:
                        pass
 
        if hasattr(self, 'nav_items_info'):
            for item in self.nav_items_info:
                item['btn'].setChecked(item.get('page_idx') == index)
    
    def toggle_navigation(self):
        """切换导航栏的展开/折叠状态"""
        self.nav_expanded = not self.nav_expanded

        # 记录导航栏状态变更
        status = "展开" if self.nav_expanded else "折叠"
        operation_log.info(f"导航栏{status}")

        self._apply_navigation_width()

        if self.nav_expanded:
            self.toggle_nav_btn.setText("◀ ◀")
            if hasattr(self, 'nav_items_info'):
                for item in self.nav_items_info:
                    item['btn'].setText(f"{item['icon']}  {item['name']}")
            if hasattr(self, 'toggle_output_btn'):
                self.toggle_output_btn.setVisible(True)
            if hasattr(self, 'output_opacity_nav_btn'):
                self.output_opacity_nav_btn.setVisible(True)
            if hasattr(self, 'clear_btn'):
                self.clear_btn.setVisible(True)
            # sub_output_frame 已移除
        else:
            self.toggle_nav_btn.setText("▶ ▶")
            if hasattr(self, 'nav_items_info'):
                for item in self.nav_items_info:
                    item['btn'].setText(item['icon'])
            if hasattr(self, 'toggle_output_btn'):
                self.toggle_output_btn.setVisible(False)
            if hasattr(self, 'output_opacity_nav_btn'):
                self.output_opacity_nav_btn.setVisible(False)
            if hasattr(self, 'clear_btn'):
                self.clear_btn.setVisible(False)
            # sub_output_frame 已移除

    def set_navbar_visible(self, visible):
        """显示或隐藏导航栏"""
        if hasattr(self, 'left_panel'):
            self.left_panel.setVisible(visible)
        self._navbar_visible = visible

    def set_navbar_position(self, position):
        """切换导航栏位置：'left' 或 'right'"""
        if position == self._navbar_position:
            return
        self._navbar_position = position
        main_layout = self.centralWidget().layout()
        if not main_layout:
            return
        main_layout.removeWidget(self.left_panel)
        if position == 'left':
            main_layout.insertWidget(0, self.left_panel)
        else:
            main_layout.addWidget(self.left_panel)

    def set_navbar_default_expanded(self, expanded):
        """设置导航栏默认展开状态（立即生效）"""
        self._navbar_default_expanded = expanded
        if self.nav_expanded != expanded:
            self.toggle_navigation()

    def _rebuild_nav_buttons(self, select_first=False):
        """根据配置重建导航按钮（更新顺序和可见性）

        Args:
            select_first: True=启动时选中第一个按钮并切换页面，False=保持当前页面选中
        """
        if not hasattr(self, 'nav_buttons_layout'):
            return

        # 1. 清空按钮子布局
        while self.nav_buttons_layout.count():
            item = self.nav_buttons_layout.takeAt(0)
            if item.widget():
                item.widget().deleteLater()

        self.nav_buttons.clear()
        self.nav_items_info.clear()

        # 2. 读取配置
        app_settings = self.config.get('app_settings', {})
        button_order = list(app_settings.get('nav_button_order', [0, 1, 2, 3, 4, 5, 6, 7]))
        button_visible = dict(app_settings.get('nav_button_visible', {str(i): True for i in range(8)}))

        # 迁移旧配置：仅当存在旧布局索引（>=8）时才执行 10 页 → 8 页迁移
        if any(x >= 8 for x in button_order):
            _old_to_new = {0: 0, 1: 1, 2: 2, 4: 3, 5: 4, 6: 5, 7: 6, 8: 7}
            button_order = [_old_to_new.get(x, -1) for x in button_order if x not in {3, 9}]
            button_order = [x for x in button_order if x >= 0]
            new_visible = {}
            for k, v in button_visible.items():
                ik = int(k)
                if ik in {3, 9}:
                    continue
                nk = _old_to_new.get(ik)
                if nk is not None:
                    new_visible[str(nk)] = v
            button_visible = new_visible

        # 兼容旧配置：确保页面 4（招投标）、6（设置）、7（部门）始终存在
        for pi in (4, 6, 7):
            if pi not in button_order:
                button_order.append(pi)
            if str(pi) not in button_visible:
                button_visible[str(pi)] = True

        is_admin = (user_type == "admin" or current_user in ("Zengjiataoadmin", "001"))

        # 3. 按 _nav_defs 构建每项的 (icon, name, content_stack_idx, nav_label)
        _nav_entries = []
        _nav_defs_full = [
            ("📄", "文件生成",   "file_gen"),
            ("📋", "订单转合同", "crm_order"),
            ("📊", "自定义报表", "custom_rpt"),
            ("📁", "文件移动",   "file_move"),
            ("🔖", "招投标授权", "pdf_watermark"),
            ("📦", "对象查询",   "obj_query"),
            ("⚙️", "设   置",   "settings"),
            ("🏢", "部门员工",   "department"),
        ]
        pmap = getattr(self, '_page_idx_map', {})
        for icon, name, pk in _nav_defs_full:
            cs_idx = pmap.get(pk, -1)
            _nav_entries.append((icon, name, cs_idx, name))

        # 4. 按配置顺序创建按钮
        for nav_idx in button_order:
            if nav_idx >= len(_nav_entries):
                continue
            icon, name, cs_idx, nav_label = _nav_entries[nav_idx]
            if cs_idx < 0:
                continue  # 页面不存在

            # 权限过滤（与 _nav_defs 的 show_to_all 对应）
            _admin_only_keys = {"custom_rpt", "obj_query", "department"}
            _nav_defs_admin_only = {2, 5, 7}  # nav_idx of admin-only entries
            if nav_idx in _nav_defs_admin_only and not is_admin:
                continue

            # 可见性过滤（settings 始终显示）
            vis_key = str(nav_idx)
            if name.strip() != "设置":
                if not button_visible.get(vis_key, True):
                    continue

            btn_text = f"{icon}  {name}" if self.nav_expanded else icon
            btn = QPushButton(btn_text)
            btn.setCheckable(True)
            btn.setMinimumHeight(10)
            btn.setCursor(Qt.CursorShape.PointingHandCursor)
            btn.setStyleSheet(get_nav_button_style(self.ui_scale_percent))
            # ✅ 传递 content_stack 索引 + 导航标签（用于区分"订单转合同"和"招投标授权"）
            btn.clicked.connect(
                lambda checked, idx=cs_idx, lbl=nav_label: self._on_nav_clicked(idx, lbl)
            )

            self.nav_buttons_layout.addWidget(btn)
            self.nav_buttons.append(btn)
            self.nav_items_info.append({
                'icon': icon, 'name': name, 'btn': btn, 'page_idx': cs_idx
            })

        # 5. 恢复选中状态
        if select_first and self.nav_items_info:
            first_page = self.nav_items_info[0]['page_idx']
            self.switch_to_page(first_page)
        else:
            current_idx = self.content_stack.currentIndex()
            for item in self.nav_items_info:
                item['btn'].setChecked(item['page_idx'] == current_idx)

        # 6. 折叠状态下按钮文本仅显示图标
        if not self.nav_expanded:
            for item in self.nav_items_info:
                item['btn'].setText(item['icon'])

    def apply_theme(self, theme_mode):
        """应用主题模式"""
        set_dialog_opacity(self)

    def _apply_condition_filter(self, headers, data_rows):
        """应用多条件筛选"""
        conditions = self._collect_data_filter_conditions()
        if not conditions:
            return data_rows
        # 建立字段名 → 列索引映射
        col_map = {}
        for idx, h in enumerate(headers):
            if h is not None:
                col_map[str(h).strip()] = idx
        filtered = []
        for entry in data_rows:
            # 兼容 (row_index, row_data) 和纯 list 两种格式
            if isinstance(entry, tuple) and len(entry) == 2:
                row_idx, row_values = entry
            else:
                row_values = entry
            match = True
            for cond in conditions:
                field = cond['field']
                op = cond['operator']
                val = cond['value'].lower()
                col_idx = col_map.get(field, -1)
                if col_idx < 0 or col_idx >= len(row_values):
                    continue
                cell_val = str(row_values[col_idx] if row_values[col_idx] is not None else '').strip().lower()
                date_val = cell_val[:10]  # 取日期部分 yyyy-MM-dd
                if op == 'contains' and val not in cell_val:
                    match = False
                elif op == 'eq' and cell_val != val:
                    match = False
                elif op == 'ne' and cell_val == val:
                    match = False
                elif op == 'starts_with' and not cell_val.startswith(val):
                    match = False
                elif op == 'ends_with' and not cell_val.endswith(val):
                    match = False
                elif op == 'empty' and cell_val:
                    match = False
                elif op == 'not_empty' and not cell_val:
                    match = False
                elif op == 'date_before' and date_val >= val:
                    match = False
                elif op == 'date_after' and date_val <= val:
                    match = False
                elif op == 'date_range' and '~' in val:
                    parts = val.split('~')
                    if not (parts[0].strip() <= date_val <= parts[1].strip()):
                        match = False
                if not match:
                    break
            if match:
                filtered.append(entry)
        return filtered

    def _resolve_excel_table_headers(self, headers):
        """根据配置解析表格需要显示的字段和顺序"""
        source_index_map = {}
        all_headers = []
        for index, header in enumerate(headers):
            header_text = str(header).strip() if header is not None else ""
            if not header_text:
                continue
            if header_text not in source_index_map:
                source_index_map[header_text] = index
                all_headers.append(header_text)

        settings = self._get_excel_table_settings(getattr(self, 'selected_operation', None))
        saved_order = [header for header in settings.get('header_order', []) if header in all_headers]
        ordered_headers = saved_order + [header for header in all_headers if header not in saved_order]
        if not ordered_headers:
            ordered_headers = all_headers.copy()

        saved_visible = settings.get('visible_headers', ordered_headers)
        visible_headers = [header for header in ordered_headers if header in saved_visible]
        if not visible_headers:
            visible_headers = ordered_headers.copy()

        return all_headers, ordered_headers, visible_headers, source_index_map

    def open_date_filter_dialog(self, anchor_widget=None):
        """打开日期选择弹窗"""
        self.selected_filter_start_date = getattr(self, 'selected_filter_start_date', None) or QDate.currentDate()
        self.selected_filter_end_date = getattr(self, 'selected_filter_end_date', None) or QDate.currentDate()
        dialog = QuickDatePickerDialog(
            self.selected_filter_start_date,
            self.selected_filter_end_date,
            self
        )
        if anchor_widget:
            dialog.position_below_widget(anchor_widget)
        if dialog.exec() == QDialog.DialogCode.Accepted:
            self.selected_filter_start_date = dialog.start_date
            self.selected_filter_end_date = dialog.end_date
            self.current_page = 1
            self.persist_contract_page_state()
            self._trigger_date_filter_update()

    def open_column_settings_dialog(self):
        """打开字段显示设置对话框"""
        operation_log.info("打开文件生成字段设置对话框")

        if not getattr(self, 'selected_operation', None):
            show_warning("提示", "请先选择功能，再设置显示字段。", self)
            return

        headers = list(getattr(self, 'current_all_headers', []))
        if not headers:
            cache_key = str(self.selected_operation)
            if cache_key in getattr(self, '_data_cache', {}):
                cached_headers, _ = self._data_cache[cache_key]
                headers = [str(header).strip() for header in cached_headers if str(header).strip()]

        if not headers:
            self.load_excel_data_to_table(self.selected_operation, force_reload=False)
            headers = list(getattr(self, 'current_all_headers', []))

        if not headers:
            show_warning("提示", "当前功能还没有可设置的字段。", self)
            return

        _, ordered_headers, visible_headers, _ = self._resolve_excel_table_headers(headers)
        current_visual_headers = self._get_current_visual_headers()
        if current_visual_headers:
            visible_headers = current_visual_headers
            ordered_headers = self._compose_full_header_order(current_visual_headers)

        dialog = ExcelFieldSettingsDialog(
            headers=headers,
            visible_headers=visible_headers,
            header_order=ordered_headers,
            parent=self
        )

        if dialog.exec() == QDialog.DialogCode.Accepted:
            visible_headers, header_order = dialog.get_settings()
            print(f"[DEBUG-文件生成] 字段设置确认 | 新可见字段数: {len(visible_headers)} | 前5项: {visible_headers[:5]}")
            self.current_visible_headers = visible_headers
            self._save_excel_table_settings(
                self.selected_operation,
                visible_headers=visible_headers,
                header_order=header_order
            )

            # 记录字段设置变更
            operation_log.info(f"文件生成字段设置已变更 | 显示字段数:{len(visible_headers)}")

            cache_key = str(self.selected_operation)
            if cache_key in getattr(self, '_data_cache', {}):
                print(f"[DEBUG-文件生成] 调用 _refresh_current_table_page()")
                self.current_page = 1
                self._refresh_current_table_page()
                print(f"[DEBUG-文件生成] _refresh_current_table_page() 完成")
            else:
                print(f"[DEBUG-文件生成] 调用 load_excel_data_to_table()")
                self.load_excel_data_to_table(self.selected_operation, force_reload=False)
                print(f"[DEBUG-文件生成] load_excel_data_to_table() 完成")
    
    def on_settings(self):
        """设置按钮事件处理 - 切换到设置页面"""
        self.switch_to_page(5)

