            target_btn.clicked.connect(lambda checked, r=i, col=2: self.browse_organize_folder(r, col))
            target_layout.addWidget(target_btn)
            self.organize_table.setCellWidget(i, 2, target_widget)

            # ✅ 修复重影问题：源文件夹和目标文件夹列已使用cellWidget，不再设置item
            # （避免widget和item重叠导致文字重影）

            file_extensions_item = QTableWidgetItem(preset.get("file_type", ""))
            contains_item = QTableWidgetItem(preset.get("contains", ""))

            # 只为非widget列设置item
