        organize_layout.addWidget(self.organize_table, 1)
        
        # 操作按钮
        organize_buttons_frame = QFrame()
        organize_buttons_layout = QHBoxLayout(organize_buttons_frame)
        
        add_preset_btn = QPushButton("添加预设")
