        tab_layout.addWidget(toolbar)
        tab_layout.addSpacing(20)
        
        # 用户列表 - 使用QTableView
        from PyQt6.QtCore import QAbstractTableModel, Qt
        class UserTableModel(QAbstractTableModel):
            """用户表格数据模型。"""
            def __init__(self, users):
                """初始化用户表格模型。"""
                super().__init__()
                self.users = users
                self.headers = ['用户ID', '用户名', '密码']
                self.pending_changes = False
            
            def rowCount(self, parent):
                """返回模型的行数。"""
                return len(self.users)
            
            def columnCount(self, parent):
                """返回模型的列数。"""
                return len(self.headers)
            
            def data(self, index, role):
                """返回模型数据。"""
                try:
                    if not index.isValid():
                        return None
                    
                    row = index.row()
                    col = index.column()
                    
                    # 检查索引是否超出范围
                    if row < 0 or row >= len(self.users) or col < 0 or col >= len(self.headers):
                        return None
                    
                    user = self.users[row]
                    
                    if role == Qt.DisplayRole or role == Qt.EditRole:
                        if col == 0:
                            return user.get('user_id', '')
                        elif col == 1:
                            return user.get('username', '')
                        elif col == 2:
                            return user.get('password', '')
                    
                    return None
                except Exception as e:
                    logging.error(f"获取数据失败: {str(e)}")
                    return None
            
            def headerData(self, section, orientation, role):
                """返回模型表头数据。"""
                if role == Qt.DisplayRole:
                    if orientation == Qt.Horizontal:
                        if 0 <= section < len(self.headers):
                            return self.headers[section]
                        return None
                    else:
                        return str(section + 1)
                return None
            
            def flags(self, index):
                """返回单元格标志。"""
                if not index.isValid() or index.column() >= len(self.headers):
                    return super().flags(index)
                flags = super().flags(index)
                if index.column() in (0, 2):  # 用户ID、密码不可编辑
                    return flags & ~Qt.ItemIsEditable
                else:
                    return flags | Qt.ItemIsEditable
            
            def setData(self, index, value, role):
                """写入模型数据。"""
                try:
                    if not index.isValid():
                        return False
                    
                    row = index.row()
                    col = index.column()
                    
                    # 检查索引是否超出范围
                    if row < 0 or row >= len(self.users) or col < 0 or col >= len(self.headers):
                        return False
                    
                    # 获取当前用户
                    current_user = self.users[row]

                    
                    # 加载完整的用户数据（包括管理员）
                    all_users_data = load_users()
                    all_users = all_users_data.get('users', [])

                    
                    # 找到要修改的用户在完整列表中的索引
                    user_index = -1
                    for i, user in enumerate(all_users):
                        if user.get('username') == current_user.get('username') or user.get('user_id') == current_user.get('user_id'):
                            user_index = i
                            break
                    
                    if user_index == -1:
                        logging.error(f"在完整用户列表中找不到用户: {current_user.get('username')} (ID: {current_user.get('user_id')})")
                        return False
                    
                    # 获取要修改的用户
                    user_to_modify = all_users[user_index]
                    
                    # 根据角色修改数据
                    if role == Qt.EditRole:
                        if col == 1:
                            # 检查用户名是否已存在
                            new_username = value
                            for i, user in enumerate(all_users):
                                if i != user_index and user.get('username') == new_username:
                                    show_warning("错误", "用户名已存在")
                                    return False
                            
                            user_to_modify['username'] = new_username
                            current_user['username'] = new_username
                    
                    # 保存完整用户列表
                    # 使用延迟保存机制，避免频繁IO操作
                    import threading
                    import time
                    
                    def delayed_save_users():
                        # 短暂延迟，避免频繁保存
                        """延迟处理保存users。"""
                        time.sleep(0.5)  # 500毫秒延迟
                        save_users({"users": all_users})
                    
                    # 启动新的保存线程
                    threading.Thread(target=delayed_save_users, daemon=True).start()
                    
                    # 刷新视图
                    self.dataChanged.emit(index, index)
                    
                    return True
                except Exception as e:
                    logging.error(f"设置数据失败: {str(e)}")
                    return False
            
            def save_changes(self):
                """保存所有待处理的修改"""
                # logging.info(f"进入save_changes方法，pending_changes={self.pending_changes}")
                if self.pending_changes:
                    try:
                        # 保存修改 - 直接使用内存中的数据
                        users_data = {"users": self.users}
                        # logging.info(f"准备保存用户数据，用户数量: {len(users_data.get('users', []))}")
                        save_users(users_data)
                        # logging.info("保存用户数据成功")
                        self.pending_changes = False
                        # logging.info("pending_changes设置为False")
                        return True
                    except Exception as e:
                        logging.error(f"保存用户修改失败: {str(e)}")
                        return False
                # logging.info("没有待保存的修改")
                return True
        
        # 加载用户数据
        # logging.info("开始加载用户数据")
        users_data = load_users()
        all_users = users_data.get('users', [])
        # logging.info(f"加载到 {len(all_users)} 个用户")
        # 不需要遍历用户列表，直接检查是否为空
        # 如果没有用户数据，创建默认管理员用户
        if not all_users:
            # logging.info("没有找到用户数据，创建默认管理员用户")
            default_admin = {
                "username": "Zengjiataoadmin",
                "password": "Zeng0213@",
                "user_id": "001",
                "created_at": get_current_time().strftime('%Y-%m-%d %H:%M:%S'),
                "role": "admin",
                "permissions": {
                    "field_format": True,
                    "field_mapping": True,
                    "template": True,
                    "feature_selection": True,
                    "database_config": True
                }
            }
            all_users.append(default_admin)
            # logging.info(f"已添加默认管理员用户: {default_admin}")
            # 保存默认管理员用户
            users_data = {"users": all_users}
            save_users(users_data)
            # logging.info("默认管理员用户已保存")
        
        # 排除ID为001的用户，只显示其他用户
        users = [user for user in all_users if user.get('user_id') != '001']
        # logging.info(f"用户列表中显示 {len(users)} 个用户")
        
        # 创建模型和视图
        self.user_model = UserTableModel(users)
        self.user_list = QTableView()
        self.user_list.setModel(self.user_model)
        self.user_list.horizontalHeader().setSectionResizeMode(QHeaderView.Interactive)
        # 加载保存的列宽
        config = load_config()
        runtime_column_widths = self.runtime_state.get('table_column_widths', {})
        column_widths = runtime_column_widths.get('user_list') or config.get('app_settings', {}).get('column_widths', {}).get('user_list', [100, 150, 150])
        
        # 确保column_widths列表长度足够
        default_widths = [100, 150, 150]
        while len(column_widths) < len(default_widths):
            column_widths.append(default_widths[len(column_widths)])
        
        self.user_list.setColumnWidth(0, column_widths[0])  # 用户ID
        self.user_list.setColumnWidth(1, column_widths[1])  # 用户名
        self.user_list.setColumnWidth(2, column_widths[2])  # 密码
        self.user_list.setEditTriggers(QTableView.DoubleClicked | QTableView.EditKeyPressed)
        # 设置选择模式为整行选择
        self.user_list.setSelectionBehavior(QTableView.SelectRows)
        self.user_list.setSelectionMode(QTableView.SingleSelection)
        self.user_list.setShowGrid(True)
        self.user_list.setAlternatingRowColors(True)
        self.user_list.setStyleSheet("""
            QTableView {
                gridline-color: #8a8a8a;
                alternate-background-color: #f7f7f7;
                selection-background-color: #dbeafe;
            }
            QHeaderView::section {
                border-right: 1px solid #8a8a8a;
                border-bottom: 1px solid #8a8a8a;
                background-color: #f2f2f2;
                padding: 4px;
            }
        """)
        
        # 连接列宽变化信号
        self.user_list.horizontalHeader().sectionResized.connect(lambda logicalIndex, oldSize, newSize: self.save_column_widths('user_list'))
        
        tab_layout.addWidget(self.user_list, 1)
        tab_layout.addSpacing(18)
        tab_layout.addWidget(self._create_password_management_widget())
        
        # 添加拉伸因子
        tab_layout.addStretch()
        
        self.notebook.addTab(tab, "用户管理")

