    def on_test_local_mysql_connection(self):
        """测试本地 MySQL 连接（后台线程执行，不阻塞 UI）"""
        host = self.local_mysql_host_entry.text().strip()
        port_str = self.local_mysql_port_entry.text().strip()
        user = self.local_mysql_user_entry.text().strip()
        password = self.local_mysql_password_entry.get().strip()
        db = self.local_mysql_db_entry.text().strip()
        self.local_mysql_status_label.setText("正在测试本地连接...（60秒超时自动停止）")
        self.local_mysql_status_label.setStyleSheet("QLabel { color: #0078D4; padding: 8px; font-size: 13px; }")
        if hasattr(self, 'local_mysql_test_btn'):
            self.local_mysql_test_btn.setEnabled(False)
        import threading
        def _test():
            import pymysql
            from PyQt6.QtCore import QMetaObject, Qt, Q_ARG
            try:
                conn = pymysql.connect(
                    host=host, port=int(port_str), user=user, password=password,
                    database=db, charset='utf8mb4', connect_timeout=60,
                    cursorclass=pymysql.cursors.DictCursor
                )
                version = conn.get_server_info()
                conn.close()
                msg = f"连接成功！服务器：{host}:{port_str} 数据库：{db} | MySQL版本：{version}"
                QMetaObject.invokeMethod(
                    self.local_mysql_status_label, "setText",
                    Qt.ConnectionType.QueuedConnection,
                    Q_ARG(str, msg)
                )
                QMetaObject.invokeMethod(
                    self.local_mysql_status_label, "setStyleSheet",
                    Qt.ConnectionType.QueuedConnection,
                    Q_ARG(str, "QLabel { color: #52C41A; padding: 8px; font-size: 13px; }")
                )
            except Exception as e:
                err = str(e)[:80]
                QMetaObject.invokeMethod(
                    self.local_mysql_status_label, "setText",
                    Qt.ConnectionType.QueuedConnection,
                    Q_ARG(str, f"连接失败: {err}")
                )
                QMetaObject.invokeMethod(
                    self.local_mysql_status_label, "setStyleSheet",
                    Qt.ConnectionType.QueuedConnection,
                    Q_ARG(str, "QLabel { color: #FF4D4F; padding: 8px; font-size: 13px; }")
                )
            if hasattr(self, 'local_mysql_test_btn'):
                QMetaObject.invokeMethod(
                    self.local_mysql_test_btn, "setEnabled",
                    Qt.ConnectionType.QueuedConnection,
                    Q_ARG(bool, True)
                )
        t = threading.Thread(target=_test, daemon=True)
        t.start()

    def _debounced_save_local_mysql_config(self):
        """推迟保存本地 MySQL 配置，停止输入 500ms 后自动保存"""
        if not hasattr(self, "_local_mysql_save_timer") or self._local_mysql_save_timer is None:
            from PyQt6.QtCore import QTimer
            self._local_mysql_save_timer = QTimer(self)
            self._local_mysql_save_timer.setSingleShot(True)
            self._local_mysql_save_timer.timeout.connect(self._do_save_local_mysql_config)
        self._local_mysql_save_timer.start(500)

    def _do_save_local_mysql_config(self):
        """安静保存本地 MySQL 配置到文件（不弹窗）"""
        from core import save_config, load_config
        cfg = load_config()
        local_cfg = {
            'enabled': self.local_mysql_enabled_checkbox.isChecked(),
            'host': self.local_mysql_host_entry.text(),
            'port': int(self.local_mysql_port_entry.text()),
            'user': self.local_mysql_user_entry.text(),
            'password': self.local_mysql_password_entry.get(),
            'database': self.local_mysql_db_entry.text()
        }
        cfg['local_mysql_config'] = local_cfg
        save_config(cfg, immediate=True)

    def _on_save_local_button_clicked(self):
        """保存本地 MySQL 配置并显示成功提示"""
        self._do_save_local_mysql_config()
        self.local_mysql_status_label.setText("本地配置已保存！")
        self.local_mysql_status_label.setStyleSheet("QLabel { color: #52C41A; padding: 8px; font-size: 13px; }")

    def _on_local_mysql_enabled_toggled(self, state):
        """即时保存本地 MySQL 启用/关闭状态"""
        enabled = bool(state)
        config = load_config()
        if 'local_mysql_config' not in config:
            config['local_mysql_config'] = {}
        config['local_mysql_config']['enabled'] = enabled
        save_config(config, immediate=True)
        status = "已启用" if enabled else "已关闭"
        print(f"[MySQL配置] 本地缓存: {status}")
        if hasattr(self, 'local_mysql_status_label'):
            self.local_mysql_status_label.setText(f"本地 MySQL {status}（配置已保存）")
    def _on_mysql_enabled_toggled(self, state):
        """即时保存 MySQL 启用/关闭状态"""
        enabled = bool(state)
        config = load_config()
        if 'mysql_config' not in config:
            config['mysql_config'] = {}
        config['mysql_config']['enabled'] = enabled
        save_config(config, immediate=True)
        status = "已启用" if enabled else "已关闭"
        print(f"[MySQL配置] 即时保存: {status}")
        if hasattr(self, 'mysql_status_label'):
            self.mysql_status_label.setText(f"MySQL {status}（配置已保存）")

    def _mysql_test_connection_worker(self, host, port, user, password, database):
        """后台线程：测试 MySQL 连接，结果存入 self._mysql_test_result"""
        import pymysql
        try:
            conn = pymysql.connect(
                host=host, port=port, user=user, password=password,
                database=database, charset='utf8mb4', connect_timeout=10,
                cursorclass=pymysql.cursors.DictCursor
            )
            with conn.cursor() as cursor:
                cursor.execute("SELECT VERSION()")
                version_row = cursor.fetchone()
            conn.close()
            server_version = version_row.get('VERSION()', '未知') if version_row else '未知'
            self._mysql_test_result = {
                'success': True, 'host': host, 'port': port,
                'database': database, 'version': server_version
            }
            try:
                if MainFrame.instance:
                    MainFrame.instance.append_output("\n=== 数据库连接状态 ===")
                    MainFrame.instance.append_output(f"服务器地址: {host}")
                    MainFrame.instance.append_output(f"端口: {port}")
                    MainFrame.instance.append_output(f"用户名: {user}")
                    MainFrame.instance.append_output(f"数据库: {database}")
                    MainFrame.instance.append_output("连接状态: 成功")
                    MainFrame.instance.append_output("====================")
            except Exception:
                pass
        except Exception as e:
            error_msg = str(e)
            self._mysql_test_result = {
                'success': False, 'host': host, 'port': port,
                'database': database, 'error': error_msg
            }
            try:
                if MainFrame.instance:
                    MainFrame.instance.append_output(f"\n=== 数据库连接失败 ===")
                    MainFrame.instance.append_output(f"错误信息: {error_msg}")
                    MainFrame.instance.append_output("====================")
            except Exception:
                pass

    def on_test_mysql_connection(self):
        """测试MySQL连接（后台线程执行，不阻塞 UI）"""
        host = self.mysql_host_entry.text().strip()
        port_str = self.mysql_port_entry.text().strip()
        user = self.mysql_user_entry.text().strip()
        password = self.mysql_password_entry.get().strip()
        database = self.mysql_db_entry.text().strip()

        try:
            port = int(port_str)
        except ValueError:
            messagebox.showerror("错误", "端口必须是数字！")
            return
        if not host:
            messagebox.showerror("错误", "服务器地址不能为空！")
            return
        if not user:
            messagebox.showerror("错误", "用户名不能为空！")
            return
        if not database:
            messagebox.showerror("错误", "数据库名称不能为空！")
            return

        # 更新 UI 为"测试中"状态
        self.mysql_status_label.setText("正在测试连接...（60秒超时自动停止）")
        self.mysql_status_label.setStyleSheet("QLabel { color: #0078d4; padding: 8px; font-size: 13px; }")
        if hasattr(self, 'mysql_test_btn'):
            self.mysql_test_btn.setEnabled(False)

        # 通过 MainFrame 的任务管理器执行连接测试（60秒超时自动停止）
        mw = self._main_window
        if mw is None:
            mw = MainFrame.instance
        if mw:
            mw.task_manager.start(
                'mysql_test_connection',
                'MySQL连接测试',
                self._mysql_test_connection_worker,
                host, port, user, password, database,
                timeout=60
            )


    def on_save_mysql_config(self):
        """保存MySQL配置"""
        try:
            # 获取配置
            mysql_config = {
                'enabled': self.mysql_enabled_checkbox.isChecked(),
                'host': self.mysql_host_entry.text(),
                'port': int(self.mysql_port_entry.text()),
                'user': self.mysql_user_entry.text(),
                'password': self.mysql_password_entry.get(),
                'database': self.mysql_db_entry.text()
            }
            
            # 保存到配置文件
            config = load_config()
            config['mysql_config'] = mysql_config
            config['local_mysql_config'] = {
                'enabled': self.local_mysql_enabled_checkbox.isChecked(),
                'host': self.local_mysql_host_entry.text(),
                'port': int(self.local_mysql_port_entry.text()),
                'user': self.local_mysql_user_entry.text(),
                'password': self.local_mysql_password_entry.get(),
                'database': self.local_mysql_db_entry.text()
            }
            save_config_with_delay(config)
            # 同步更新 SettingsDialog 和 MainFrame 的 config 引用，防止任一方的后续保存操作覆盖 MySQL 配置
            self.config = config
            if hasattr(self, '_main_window') and self._main_window and hasattr(self._main_window, 'config'):
                self._main_window.config = config
            self.apply_settings_immediately({'mysql'})

            messagebox.showinfo("成功", "MySQL配置已保存！")
        except ValueError:
            messagebox.showerror("错误", "端口必须是数字！")
        except Exception as e:
            messagebox.showerror("错误", f"保存MySQL配置失败: {str(e)}")

