    def _get_provider_preset_name(self, pid):
        """根据 provider type id 获取预设名称"""
        preset = self._preset_map.get(pid, {})
        return preset.get('name', pid)

    def _get_provider_color(self, ptype):
        """根据 provider type 获取颜色"""
        preset = self._preset_map.get(ptype, {})
        return preset.get('color', '#666')

    def _refresh_api_cards(self):
        """刷新 API 卡片列表 —— 清除并重建所有卡片"""
        # 清空现有卡片
        while self._api_cards_layout.count():
            item = self._api_cards_layout.takeAt(0)
            if item.widget():
                item.widget().deleteLater()

        self._api_config_widgets = {}
        self._api_card_widgets = {}

        for provider_data in self._api_providers_data:
            pid = provider_data.get('id', '')
            ptype = provider_data.get('type', '')
            preset = self._preset_map.get(ptype, {})
            color = preset.get('color', '#666')
            name = provider_data.get('name', preset.get('name', ptype))
            pcfg = {
                'api_key': provider_data.get('api_key', ''),
                'api_url': provider_data.get('api_url', preset.get('default_url', '')),
                'model': provider_data.get('model', ''),
                'enabled': provider_data.get('enabled', False),
            }
            is_active = (pid == self._api_active_id)

            # 卡片 GroupBox
            group = QGroupBox()
            group.setStyleSheet(f"""
                QGroupBox {{
                    font-size: 13px; font-weight: bold; color: {color};
                    border: 1px solid #ddd; border-radius: 6px;
                    margin-top: 12px; padding: 12px 8px 8px 8px;
                }}
                QGroupBox::title {{
                    subcontrol-origin: margin; left: 12px; padding: 0 6px;
                }}
            """)

            card_layout = QVBoxLayout(group)
            card_layout.setSpacing(4)

            # 第一行：启用单选框 + 提供商类型标签 + 删除按钮
            top_row = QHBoxLayout()

            # 启用单选框（互斥 —— 只允许一个启用）
            enabled_rb = QRadioButton()
            enabled_rb.setChecked(is_active)
            enabled_rb.setToolTip("勾选以启用此 API 配置（仅一个生效）")
            enabled_rb.toggled.connect(lambda checked, pid=pid: self._on_api_enabled_toggled(pid, checked))
            top_row.addWidget(enabled_rb)

            # 类型标签
            type_label = QLabel(f"[{preset.get('name', ptype)}]")
            type_label.setStyleSheet(f"color: {color}; font-weight: bold; font-size: 12px;")
            top_row.addWidget(type_label)

            # 自定义名称
            name_entry = QLineEdit()
            name_entry.setText(name)
            name_entry.setPlaceholderText("自定义名称（如：我的 DeepSeek）")
            name_entry.setFixedWidth(180)
            name_entry.textChanged.connect(lambda text, pid=pid: self._on_api_field_changed(pid, 'name', text))
            top_row.addWidget(name_entry)

            top_row.addStretch()

            # 删除按钮
            del_btn = QPushButton("🗑 删除")
            del_btn.setFixedHeight(28)
            del_btn.setMinimumWidth(70)
            del_btn.setStyleSheet("QPushButton { color: #E74C3C; border: 1px solid #E74C3C; border-radius: 3px; padding: 0 10px; } QPushButton:hover { background: #FDEDEC; }")
            del_btn.clicked.connect(lambda checked, pid=pid: self._delete_api_provider(pid))
            top_row.addWidget(del_btn)

            card_layout.addLayout(top_row)

            # 表单行
            form_grid = QGridLayout()
            form_grid.setSpacing(6)
            form_grid.setContentsMargins(24, 4, 8, 4)

            # API Key
            form_grid.addWidget(QLabel("API Key:"), 0, 0)
            key_layout = QHBoxLayout()
            key_entry = QLineEdit()
            key_entry.setText(pcfg['api_key'])
            key_entry.setEchoMode(QLineEdit.EchoMode.Password)
            key_entry.setPlaceholderText("输入 API Key...")
            key_entry.textChanged.connect(lambda text, pid=pid: self._on_api_field_changed(pid, 'api_key', text))
            key_layout.addWidget(key_entry, 1)

            show_btn = QPushButton("👁")
            show_btn.setFixedSize(30, 26)
            show_btn.setCheckable(True)
            show_btn.toggled.connect(lambda checked, e=key_entry: e.setEchoMode(
                QLineEdit.EchoMode.Normal if checked else QLineEdit.EchoMode.Password))
            key_layout.addWidget(show_btn)
            form_grid.addLayout(key_layout, 0, 1)

            # 模型
            form_grid.addWidget(QLabel("模型:"), 1, 0)
            model_combo = QComboBox()
            preset_models = preset.get('models', [])
            if pcfg['model'] and pcfg['model'] not in preset_models:
                # 如果模型不在预设列表中，添加为可编辑项
                model_combo.setEditable(True)
                model_combo.addItems(preset_models)
                model_combo.setCurrentText(pcfg['model'])
            else:
                model_combo.addItems(preset_models)
                if pcfg['model']:
                    model_combo.setCurrentText(pcfg['model'])
                elif preset_models:
                    model_combo.setCurrentIndex(0)
            model_combo.currentTextChanged.connect(lambda text, pid=pid: self._on_api_field_changed(pid, 'model', text))
            form_grid.addWidget(model_combo, 1, 1)

            # API 地址
            form_grid.addWidget(QLabel("API 地址:"), 2, 0)
            url_entry = QLineEdit()
            url_entry.setText(pcfg['api_url'])
            url_entry.setPlaceholderText(preset.get('default_url', ''))
            url_entry.textChanged.connect(lambda text, pid=pid: self._on_api_field_changed(pid, 'api_url', text))
            form_grid.addWidget(url_entry, 2, 1)

            # 帮助链接
            help_url = preset.get('help_url', '')
            if help_url:
                help_label = QLabel(f"<a href='{help_url}' style='color: #1890FF;'>获取 API Key →</a>")
                help_label.setOpenExternalLinks(True)
                form_grid.addWidget(help_label, 3, 0, 1, 2)

            card_layout.addLayout(form_grid)
            self._api_cards_layout.addWidget(group)

            # 存储控件引用
            self._api_config_widgets[pid] = {
                'key_entry': key_entry,
                'model_combo': model_combo,
                'url_entry': url_entry,
                'enabled_rb': enabled_rb,
                'name_entry': name_entry,
            }
            self._api_card_widgets[pid] = {
                'group': group,
                'type_label': type_label,
            }

        # 末尾弹簧
        self._api_cards_layout.addStretch()

    def _on_api_field_changed(self, pid, field, value):
        """API 卡片字段变化时同步更新内存数据"""
        # URL 字段自动去除首尾空白（含换行符）
        if field == 'api_url' and isinstance(value, str):
            value = value.strip()
        for p in self._api_providers_data:
            if p.get('id') == pid:
                p[field] = value
                return

    def _on_api_enabled_toggled(self, pid, checked):
        """启用单选按钮切换 —— 确保只有一个被选中"""
        if not checked:
            return
        # 更新内存数据
        for p in self._api_providers_data:
            p['enabled'] = (p.get('id') == pid)
        self._api_active_id = pid
        # 刷新所有单选按钮状态
        for other_pid, widgets in (self._api_config_widgets or {}).items():
            rb = widgets.get('enabled_rb')
            if rb and other_pid != pid:
                rb.blockSignals(True)
                rb.setChecked(False)
                rb.blockSignals(False)

    def _add_api_provider(self):
        """弹出对话框添加新的 API 配置"""
        dialog = QDialog(self)
        dialog.setWindowTitle("添加 API 配置")
        dialog.setFixedSize(500, 380)
        dialog.setWindowFlags(dialog.windowFlags() | Qt.WindowType.FramelessWindowHint)

        layout = QVBoxLayout(dialog)
        layout.setSpacing(12)

        # 步骤说明
        step_label = QLabel("① 选择 AI 模型提供商，② 填写配置信息")
        step_label.setStyleSheet("color: #666; font-size: 13px;")
        layout.addWidget(step_label)

        form = QFormLayout()
        form.setSpacing(10)

        # 选择提供商（模型）
        provider_combo = QComboBox()
        for preset in self._providers_preset:
            provider_combo.addItem(f"{preset['name']}  ({', '.join(preset['models'][:3])}{'…' if len(preset['models']) > 3 else ''})", preset['id'])
        provider_combo.setCurrentIndex(0)
        form.addRow("选择模型:", provider_combo)

        # 自定义名称
        name_entry = QLineEdit()
        name_entry.setPlaceholderText("例如：我的 DeepSeek、公司小米账号…")
        form.addRow("配置名称:", name_entry)

        # API Key
        key_entry = QLineEdit()
        key_entry.setEchoMode(QLineEdit.EchoMode.Password)
        key_entry.setPlaceholderText("粘贴 API Key…")
        form.addRow("API Key:", key_entry)

        # 模型
        model_combo = QComboBox()
        model_combo.setEditable(True)
        first_preset = self._providers_preset[0]
        model_combo.addItems(first_preset['models'])
        model_combo.setCurrentIndex(0)
        form.addRow("默认模型:", model_combo)

        # API 地址
        url_entry = QLineEdit()
        url_entry.setText(first_preset['default_url'])
        url_entry.setPlaceholderText("https://api.xxx.com/v1/chat/completions")
        form.addRow("API 地址:", url_entry)

        # 帮助链接
        help_label = QLabel(f"<a href='{first_preset['help_url']}' style='color: #1890FF;'>获取 API Key →</a>")
        help_label.setOpenExternalLinks(True)
        form.addRow("", help_label)

        # 当选择不同提供商时自动更新模型列表、URL 和帮助链接
        def on_provider_changed(idx):
            pid = provider_combo.currentData()
            preset = self._preset_map.get(pid, {})
            model_combo.clear()
            model_combo.addItems(preset.get('models', []))
            model_combo.setCurrentIndex(0)
            url_entry.setText(preset.get('default_url', ''))
            help_label.setText(f"<a href='{preset.get('help_url', '')}' style='color: #1890FF;'>获取 API Key →</a>")
        provider_combo.currentIndexChanged.connect(on_provider_changed)

        layout.addLayout(form)

        # 按钮
        btn_layout = QHBoxLayout()
        btn_layout.addStretch()
        cancel_btn = QPushButton("取消")
        cancel_btn.clicked.connect(dialog.reject)
        btn_layout.addWidget(cancel_btn)

        ok_btn = QPushButton("确定添加")
        ok_btn.setStyleSheet("QPushButton { background-color: #1890FF; color: white; border-radius: 4px; padding: 6px 16px; } QPushButton:hover { background-color: #40A9FF; }")
        btn_layout.addWidget(ok_btn)
        layout.addLayout(btn_layout)

        def on_ok():
            ptype = provider_combo.currentData()
            preset = self._preset_map.get(ptype, {})
            custom_name = name_entry.text().strip()
            api_key = key_entry.text().strip()
            model = model_combo.currentText().strip()
            api_url = url_entry.text().strip()

            if not api_key:
                frameless_message_box(dialog, "提示", "请输入 API Key")
                return
            if not api_url:
                frameless_message_box(dialog, "提示", "请输入 API 地址")
                return
            if not model:
                frameless_message_box(dialog, "提示", "请选择或输入模型名称")
                return

            # 生成唯一 ID
            new_id = f"{ptype}_{uuid.uuid4().hex[:8]}"
            if not custom_name:
                custom_name = preset.get('name', ptype)

            # 如果这是第一个 API，默认启用
            enabled = (len(self._api_providers_data) == 0)

            new_provider = {
                'id': new_id,
                'type': ptype,
                'name': custom_name,
                'api_key': api_key,
                'api_url': api_url,
                'model': model,
                'enabled': enabled,
            }
            self._api_providers_data.append(new_provider)
            if enabled:
                self._api_active_id = new_id

            self._save_api_config_silent()
            self._refresh_api_cards()
            dialog.accept()

        ok_btn.clicked.connect(on_ok)

        dialog.exec()

    def _delete_api_provider(self, pid):
        """删除指定的 API 配置"""
        target = next((p for p in self._api_providers_data if p.get('id') == pid), None)
        if not target:
            return
        name = target.get('name', pid)
        reply = frameless_message_box(self, "确认删除",
            f"确定要删除 API 配置「{name}」吗？\n此操作不可恢复。",
            QMessageBox.StandardButton.Yes | QMessageBox.StandardButton.No, QMessageBox.StandardButton.No)
        if reply != QMessageBox.StandardButton.Yes:
            return

        was_enabled = target.get('enabled', False)
        self._api_providers_data = [p for p in self._api_providers_data if p.get('id') != pid]

        if was_enabled and self._api_providers_data:
            # 如果删除的是当前启用的，自动启用第一个
            self._api_providers_data[0]['enabled'] = True
            self._api_active_id = self._api_providers_data[0]['id']
        elif not self._api_providers_data:
            self._api_active_id = ''

        self._save_api_config_silent()
        self._refresh_api_cards()

    def _save_api_config(self):
        """保存 API 配置（用户点击按钮时调用，带提示弹窗）"""
        self._save_api_config_silent()
        active_name = ''
        for p in self._api_providers_data:
            if p.get('id') == self._api_active_id:
                active_name = p.get('name', self._api_active_id)
                break
        count = len(self._api_providers_data)
        config_file = get_config_path(for_save=True)
        frameless_message_box(self, "成功", f"API 配置已保存到:\n{config_file}\n\n已配置 {count} 个 API | 当前启用: {active_name or '(无)'}")
        print("[API 配置] 已保存")

    def _save_api_config_silent(self):
        """静默保存 API 配置（添加/删除后自动调用，无弹窗）"""
        # 保存前清理 URL 字段（去除首尾空白/换行符）
        for p in self._api_providers_data:
            if isinstance(p.get('api_url'), str):
                p['api_url'] = p['api_url'].strip()
        save_data = {
            'providers': list(self._api_providers_data),
            'active': self._api_active_id,
        }
        config = load_config()
        config['llm_providers'] = save_data
        save_config(config, immediate=True)
        # 同步更新 SettingsDialog 和 MainFrame 的 config 引用，防止任一方的后续保存操作覆盖 API 配置
        self.config = config
        if hasattr(self, '_main_window') and self._main_window and hasattr(self._main_window, 'config'):
            self._main_window.config = config
        print("[API 配置] 已静默保存")

    def _test_api_connection(self):
        """测试 API 连接 —— 测试当前启用的提供商"""
        # 找到启用且有 key 的提供商进行测试
        for provider_data in self._api_providers_data:
            if provider_data.get('enabled') and provider_data.get('api_key', '').strip():
                url = provider_data.get('api_url', '').strip()
                key = provider_data.get('api_key', '').strip()
                model = provider_data.get('model', '').strip()
                name = provider_data.get('name', provider_data.get('type', ''))
                try:
                    response = perform_requests_request(
                        'post', url,
                        headers={'Authorization': f'Bearer {key}', 'Content-Type': 'application/json'},
                        json={'model': model, 'messages': [{'role': 'user', 'content': 'Hi'}], 'max_tokens': 10},
                        timeout=15,
                    )
                    if response.status_code == 200:
                        frameless_message_box(self, "连接成功", f"✅「{name}」连接成功！\n模型: {model}")
                        print(f"[API 配置] {name} 连接成功")
                    else:
                        frameless_message_box(self, "连接失败", f"❌「{name}」连接失败\nHTTP {response.status_code}: {response.text[:200]}")
                        print(f"[API 配置] 测试失败 HTTP {response.status_code}: {response.text[:200]}")
                except Exception as e:
                    frameless_message_box(self, "连接失败", f"❌「{name}」连接失败\n{str(e)[:300]}")
                    print(f"[API 配置] 测试失败: {e}")
                return
        frameless_message_box(self, "提示", "没有可测试的 API 配置。\n请先启用一个并填写 API Key。")
        print("[API 配置] 没有可测试的提供商（需启用并填写 API Key）")

    def refresh_user_list(self):
        """刷新用户列表"""
        if hasattr(self, 'user_model'):
            # 重新加载用户数据
            users_data = load_users()
            users = [user for user in users_data.get('users', []) if user.get('user_id') != '001']
            
            # 更新模型数据
            self.user_model.users = users
            self.user_model.layoutChanged.emit()

    def on_user_double_click(self, index):
        """双击用户行切换用户"""
        row = index.row()
        user = self.user_model.users[row]
        username = user.get('username')
        
        # 弹窗提示是否登录
        if ask_yes_no("确认登录", f"确定要登录用户 {username} 吗？"):
            # 更新全局变量
            global current_user, user_type
            current_user = username
            user_type = "member"
            save_user_cache(username, "member")
            
            # 显示成功信息并重启程序
            show_info("成功", "用户切换成功，程序将重启")
            import time
            time.sleep(1)
            # 重启程序
            os.execl(sys.executable, sys.executable, *sys.argv)

    def on_open_cache_folder(self):
        """打开缓存文件夹"""
        path = self.log_dir_text.text() if hasattr(self, 'log_dir_text') else 'Cache'
        if os.path.exists(path):
            os.startfile(path)
        else:
            messagebox.showerror("错误", "缓存文件夹不存在")

    def on_clear_cache(self):
        """清除缓存文件"""
        path = self.log_dir_text.text() if hasattr(self, 'log_dir_text') else 'Cache'
        if not os.path.exists(path):
            messagebox.showerror("错误", "缓存文件夹不存在")
            return
        
        if messagebox.askyesno("确认", "确定要清除所有缓存文件吗？"):
            try:
                for f in os.listdir(path):
                    fp = os.path.join(path, f)
                    if os.path.isfile(fp):
                        os.remove(fp)
                messagebox.showinfo("成功", "缓存已清除")
            except Exception as e:
                messagebox.showerror("错误", str(e))
    
    def on_add_organize_preset(self):
        """添加文件整理预设"""
        # 在表格末尾添加一行
        row = self.organize_table.rowCount()
        self.organize_table.insertRow(row)
        
        # 创建默认单元格
        name_item = QTableWidgetItem("新预设")
        self.organize_table.setItem(row, 0, name_item)
        
        # 源文件夹带有浏览按钮
        source_widget = QFrame()
        source_layout = QHBoxLayout(source_widget)
        source_layout.setContentsMargins(0, 0, 0, 0)
        source_edit = QLineEdit("")
        source_layout.addWidget(source_edit)
        source_btn = QPushButton("浏览")
        source_btn.setFixedWidth(60)
        source_btn.clicked.connect(lambda checked, r=row, col=1: self.browse_organize_folder(r, col))
        source_layout.addWidget(source_btn)
        self.organize_table.setCellWidget(row, 1, source_widget)
        
        # 目标文件夹带有浏览按钮
        target_widget = QFrame()
        target_layout = QHBoxLayout(target_widget)
        target_layout.setContentsMargins(0, 0, 0, 0)
        target_edit = QLineEdit("")
        target_layout.addWidget(target_edit)
        target_btn = QPushButton("浏览")
        target_btn.setFixedWidth(60)
        target_btn.clicked.connect(lambda checked, r=row, col=2: self.browse_organize_folder(r, col))
        target_layout.addWidget(target_btn)
        self.organize_table.setCellWidget(row, 2, target_widget)

        # ✅ 修复重影问题：源文件夹和目标文件夹列已使用cellWidget，不再设置item
        file_extensions_item = QTableWidgetItem("")
        contains_item = QTableWidgetItem("")

        # 只为非widget列设置item
        self.organize_table.setItem(row, 3, file_extensions_item)
        self.organize_table.setItem(row, 4, contains_item)

        # ✅ 修复：直接连接到保存函数
        source_edit.textChanged.connect(lambda text: self.save_organize_presets())
        target_edit.textChanged.connect(lambda text: self.save_organize_presets())
        
        # 选中新添加的行并开始编辑预设名
        self.organize_table.selectRow(row)
        self.organize_table.editItem(name_item)
    
    def on_organize_table_item_changed(self, item):
        """表格单元格变化事件，实时保存预设设置"""
        self.save_organize_presets()

    def update_hidden_item(self, item, text):
        """更新隐藏的item并保存配置"""
        if item:
            item.setText(text)
            self.save_organize_presets()
            
    def save_organize_presets(self):
        """保存文件整理预设到配置文件"""
        # 获取表格中的所有预设
        presets = []
        row_count = self.organize_table.rowCount()
        for i in range(row_count):
            name_item = self.organize_table.item(i, 0)
            file_extensions_item = self.organize_table.item(i, 3)
            contains_item = self.organize_table.item(i, 4)

            # ✅ 修复：从cellWidget中获取源文件夹和目标文件夹的值
            source_widget = self.organize_table.cellWidget(i, 1)
            target_widget = self.organize_table.cellWidget(i, 2)

            source_dir = ''
            target_dir = ''

            if source_widget:
                # 从widget中查找QLineEdit
                line_edit = source_widget.findChild(QLineEdit)
                if line_edit:
                    source_dir = line_edit.text().strip()

            if target_widget:
                # 从widget中查找QLineEdit
                line_edit = target_widget.findChild(QLineEdit)
                if line_edit:
                    target_dir = line_edit.text().strip()

            # 只有预设名不为空的行才保存
            if name_item and name_item.text().strip():
                preset = {
                    'name': name_item.text().strip(),
                    'source_dir': source_dir,
                    'target_dir': target_dir,
                    'file_type': file_extensions_item.text().strip() if file_extensions_item else '',
                    'contains': contains_item.text().strip() if contains_item else ''
                }
                presets.append(preset)
        
        # 保存预设
        config = load_config()
        if 'directory_config' not in config:
            config['directory_config'] = {}
        config['directory_config']['presets'] = presets
        # 立即保存，确保设置立即生效
        save_config(config, immediate=False)
        self.apply_settings_immediately({'path', 'table_source'})
    
    def on_delete_organize_preset(self):
        """删除文件整理预设"""
        if hasattr(self, 'organize_table'):
            # 获取所有选中的行，不限制列
            selected_rows = set()
            for item in self.organize_table.selectedItems():
                selected_rows.add(item.row())
            
            if not selected_rows:
                show_warning("错误", "请选择要删除的预设", self)
                return
            
            # 获取第一个选中的行索引
            row = sorted(selected_rows)[0]
            
            # 确认删除
            if ask_yes_no("确认", "确定要删除选中的预设吗？", self):
                # 从表格中删除行
                self.organize_table.removeRow(row)
                # 保存配置
                self.on_organize_table_item_changed(None)
    
    def on_organize_table_cell_double_clicked(self, row, column):
        """表格单元格双击事件，用于选择文件夹"""
        if column == 1 or column == 2:  # 源文件夹或目标文件夹列
            self.browse_organize_folder(row, column)

    def browse_organize_folder(self, row, column):
        """浏览文件夹并更新到表格"""
        from PyQt6.QtWidgets import QFileDialog
        
        # 确定要更新的QLineEdit
        cell_widget = self.organize_table.cellWidget(row, column)
        if not cell_widget:
            return
            
        line_edit = cell_widget.findChild(QLineEdit)
        if not line_edit:
            return
            
        # 获取当前文本框的内容作为初始路径
        current_path = line_edit.text().strip()
        if not current_path or not os.path.exists(current_path):
            current_path = ""
            
        dir_path = QFileDialog.getExistingDirectory(self, "选择文件夹", current_path)
        if dir_path:
            # 更新文本框内容
            line_edit.setText(dir_path)
            
            # 同时更新隐藏的item以保持兼容性
            hidden_item = self.organize_table.item(row, column)
            if hidden_item:
                hidden_item.setText(dir_path)
                
            # 保存配置
            self.save_organize_presets()

    def on_restore_default(self):
        """恢复默认设置"""
        if messagebox.askyesno("确认", "确定要恢复默认设置吗？程序将重启。"):
            # 加载默认配置文件
            default_config_path = get_default_profile_path()
            if not default_config_path.exists():
                try:
                    import sys
                    if getattr(sys, 'frozen', False):
                        default_config_path = get_default_profile_path()
                    else:
                        default_config_path = get_default_profile_path()
                except:
                    pass
            
            if default_config_path.exists():
                try:
                    # 读取默认配置
                    with open(default_config_path, 'r', encoding='utf-8') as f:
                        default_config = json.load(f)
                    # 获取个人配置文件路径
                    config_path = get_config_path(for_save=True)
                    # 确保目录存在
                    config_path.parent.mkdir(parents=True, exist_ok=True)
                    # 保存默认配置到个人配置文件
                    with open(config_path, 'w', encoding='utf-8') as f:
                        json.dump(default_config, f, ensure_ascii=False, indent=2)
                    # 清除配置缓存，确保下次加载时使用新配置
                    global _config_cache, _config_last_modified, _current_config_path
                    _config_cache = None
                    _config_last_modified = 0
                    _current_config_path = None
                    logging.info(f"默认配置已同步到个人配置文件: {config_path}")
                except Exception as e:
                    logging.error(f"恢复默认配置失败: {str(e)}")
                    messagebox.showerror("错误", f"恢复默认配置失败: {str(e)}")
                    return
            else:
                messagebox.showerror("错误", "默认配置文件不存在，无法恢复默认设置")
                return
            # 重启
            os.execl(sys.executable, sys.executable, *sys.argv)

    def save_column_widths(self, table_name):
        """保存表格列宽设置"""
        # ✅ 初始化/恢复期间禁止保存，防止默认宽度覆盖用户已保存的宽度
        if getattr(self, '_suspending_column_width_save', False):
            print(f"[列宽保存] ⏸️ 跳过（初始化中）: {table_name}")
            return
        config = load_config()
        if 'app_settings' not in config:
            config['app_settings'] = {}
        if 'column_widths' not in config['app_settings']:
            config['app_settings']['column_widths'] = {}
        widths = None

        # 根据表格名称保存列宽
        if table_name == 'mapping_table' and hasattr(self, 'mapping_table'):
            widths = []
            for i in range(self.mapping_table.columnCount()):
                widths.append(self.mapping_table.columnWidth(i))
            config['app_settings']['column_widths']['mapping_table'] = widths
        elif table_name == 'template_table' and hasattr(self, 'template_table'):
            widths = []
            for i in range(self.template_table.columnCount()):
                widths.append(self.template_table.columnWidth(i))
            config['app_settings']['column_widths']['template_table'] = widths
        elif table_name == 'crm_template_table' and hasattr(self, 'crm_template_table'):
            widths = []
            for i in range(self.crm_template_table.columnCount()):
                widths.append(self.crm_template_table.columnWidth(i))
            config['app_settings']['column_widths']['crm_template_table'] = widths
        elif table_name == 'user_list' and hasattr(self, 'user_list'):
            widths = []
            # QTableView 需要通过模型获取列数
            model = self.user_list.model()
            if model:
                for i in range(model.columnCount(None)):
                    widths.append(self.user_list.columnWidth(i))
            config['app_settings']['column_widths']['user_list'] = widths
        elif table_name == 'feature_table' and hasattr(self, 'feature_table'):
            widths = []
            for i in range(self.feature_table.columnCount()):
                widths.append(self.feature_table.columnWidth(i))
            config['app_settings']['column_widths']['feature_table'] = widths
        elif table_name == 'product_table' and hasattr(self, 'product_table'):
            widths = []
            for i in range(self.product_table.columnCount()):
                widths.append(self.product_table.columnWidth(i))
            config['app_settings']['column_widths']['product_table'] = widths
        elif table_name == 'organize_table' and hasattr(self, 'organize_table'):
            widths = []
            for i in range(self.organize_table.columnCount()):
                widths.append(self.organize_table.columnWidth(i))
            config['app_settings']['column_widths']['organize_table'] = widths
        elif table_name == 'crm_field_mapping_list_table' and hasattr(self, 'crm_field_mapping_list_table'):
            widths = []
            for i in range(self.crm_field_mapping_list_table.columnCount()):
                widths.append(self.crm_field_mapping_list_table.columnWidth(i))
            config['app_settings']['column_widths']['crm_field_mapping_list_table'] = widths
        elif table_name == 'opp_field_mapping_list_table' and hasattr(self, 'opp_field_mapping_list_table'):
            widths = []
            for i in range(self.opp_field_mapping_list_table.columnCount()):
                widths.append(self.opp_field_mapping_list_table.columnWidth(i))
            config['app_settings']['column_widths']['opp_field_mapping_list_table'] = widths
        elif table_name == 'crm_mapping_table' and hasattr(self, 'crm_mapping_table'):
            widths = []
            for i in range(self.crm_mapping_table.columnCount()):
                widths.append(self.crm_mapping_table.columnWidth(i))
            config['app_settings']['column_widths']['crm_mapping_table'] = widths
        elif table_name == 'crm_unified_mapping_table' and hasattr(self, 'crm_unified_mapping_table'):
            widths = []
            for i in range(self.crm_unified_mapping_table.columnCount()):
                widths.append(self.crm_unified_mapping_table.columnWidth(i))
            config['app_settings']['column_widths']['crm_unified_mapping_table'] = widths
        elif table_name == 'bid_template_table' and hasattr(self, 'bid_template_table'):
            widths = []
            for i in range(self.bid_template_table.columnCount()):
                widths.append(self.bid_template_table.columnWidth(i))
            config['app_settings']['column_widths']['bid_template_table'] = widths
        elif table_name == 'opp_unified_mapping_table' and hasattr(self, 'opp_unified_mapping_table'):
            widths = []
            for i in range(self.opp_unified_mapping_table.columnCount()):
                widths.append(self.opp_unified_mapping_table.columnWidth(i))
            config['app_settings']['column_widths']['opp_unified_mapping_table'] = widths
        elif table_name == 'opp_word_mapping_table' and hasattr(self, 'opp_word_mapping_table'):
            widths = []
            for i in range(self.opp_word_mapping_table.columnCount()):
                widths.append(self.opp_word_mapping_table.columnWidth(i))
            config['app_settings']['column_widths']['opp_word_mapping_table'] = widths
        else:
            # 动态列表格（如 opp_unified_mapping_table_2col / crm_unified_mapping_table_7col）
            import re
            m = re.match(r'^(.+)_(\d+)col$', table_name)
            if m:
                base_name = m.group(1)
                table = getattr(self, base_name, None)
                if table is not None:
                    widths = []
                    for i in range(table.columnCount()):
                        widths.append(table.columnWidth(i))
                    config['app_settings']['column_widths'][table_name] = widths

        if widths is not None:
            rts_path = get_user_runtime_state_path(for_save=True)
            print(f"[列宽保存] 💾 {table_name} = {widths} → {rts_path}")
            save_user_runtime_state({
                'table_column_widths': {
                    table_name: widths
                }
            }, immediate=True, merge=True)
            # 同步更新内存中的 runtime_state，避免后续读取到旧数据
            if 'table_column_widths' not in self.runtime_state:
                self.runtime_state['table_column_widths'] = {}
            self.runtime_state['table_column_widths'][table_name] = widths

        # 保存配置并同步更新内存（立即写入，确保重启后列宽不丢失）
        save_config(config, immediate=True)
        if widths is not None:
            if 'app_settings' not in self.config:
                self.config['app_settings'] = {}
            if 'column_widths' not in self.config['app_settings']:
                self.config['app_settings']['column_widths'] = {}
            self.config['app_settings']['column_widths'][table_name] = widths

    def _filter_mapping_table(self, text):
        """根据搜索文本过滤字段配置表格行（模糊搜索源字段和目标字段）"""
        if not hasattr(self, 'mapping_table'):
            return
        search_text = text.strip().lower()
        for row in range(self.mapping_table.rowCount()):
            src_item = self.mapping_table.item(row, 0)
            dst_item = self.mapping_table.item(row, 1)
            if search_text:
                src_match = search_text in src_item.text().strip().lower() if src_item else False
                dst_match = search_text in dst_item.text().strip().lower() if dst_item else False
                match = src_match or dst_match
            else:
                match = True
            self.mapping_table.setRowHidden(row, not match)

    def on_save_mappings(self, *args, immediate=False):
        """保存字段映射和格式"""
        if self._suspend_mapping_save:
            return
        if immediate:
            self._pending_setting_change_types.update({'mapping', 'special_columns'})
            self._flush_mapping_save()
        else:
            self.schedule_mapping_save({'mapping', 'special_columns'})

    def on_add_mapping(self):
        """添加映射字段"""
        from PyQt6.QtWidgets import QComboBox
        from PyQt6.QtCore import QEvent, QObject
        
        # 鼠标滚轮事件过滤器类
        class WheelEventFilter(QObject):
            """通用滚轮事件过滤器。"""
            def eventFilter(self, obj, event):
                """拦截并处理目标事件。"""
                if event.type() == QEvent.Wheel:
                    return True  # 阻止鼠标滚轮事件
                return False
        
        row_position = self.mapping_table.rowCount()
        self._suspend_mapping_save = True
        self.mapping_table.blockSignals(True)
        self.mapping_table.insertRow(row_position)
        self.mapping_table.setItem(row_position, 0, QTableWidgetItem("新字段"))
        self.mapping_table.setItem(row_position, 1, QTableWidgetItem(""))
        
        # 添加格式下拉框
        format_combo = QComboBox()
        format_options = [
            {"name": "文本", "format": "{}"},
            {"name": "日期 (YYYY-MM-DD)", "format": "%Y-%m-%d"},
            {"name": "日期 (YYYY年MM月DD日)", "format": "%Y年%m月%d日"},
            {"name": "人民币", "format": "￥{:,.2f}"},
            {"name": "金额", "format": "{:,.2f}"},
            {"name": "数字", "format": "{:,.2f}"},
            {"name": "整数", "format": "{:,.0f}"}
        ]
        format_combo.addItem("", "")  # 空选项
        for opt in format_options:
            format_combo.addItem(opt["name"], opt["format"])
        
        # 安装鼠标滚轮事件过滤器，并保持引用
        wheel_filter = WheelEventFilter()
        if not hasattr(self, 'mapping_table_wheel_filters'):
            self.mapping_table_wheel_filters = []
        self.mapping_table_wheel_filters.append(wheel_filter)
        format_combo.installEventFilter(wheel_filter)
        
        # 连接格式变化事件到保存方法
        format_combo.currentIndexChanged.connect(self.on_save_mappings)
        
        self.mapping_table.setCellWidget(row_position, 2, format_combo)
        self.mapping_table.blockSignals(False)
        self._suspend_mapping_save = False
        
        # 合并为一次保存，避免新增行时重复刷新主界面
        self.on_save_mappings(immediate=True)
        # 重新应用搜索过滤
        if hasattr(self, 'mapping_search_input'):
            self._filter_mapping_table(self.mapping_search_input.text())

    def on_delete_mapping(self):
        """删除映射字段"""
        self._suspend_mapping_save = True
        self.mapping_table.blockSignals(True)
        selected_row = self.mapping_table.currentRow()
        if selected_row >= 0:
            self.mapping_table.removeRow(selected_row)
        else:
            # 如果没有选择行，删除最后一行
            if self.mapping_table.rowCount() > 0:
                self.mapping_table.removeRow(self.mapping_table.rowCount() - 1)
        self.mapping_table.blockSignals(False)
        self._suspend_mapping_save = False
        # 立即保存
        self.on_save_mappings(immediate=True)
        # 重新应用搜索过滤
        if hasattr(self, 'mapping_search_input'):
            self._filter_mapping_table(self.mapping_search_input.text())

    def on_save_crm_mappings(self, *args, immediate=False):
        """保存CRM字段映射设置"""
        field_mapping = {}
        special_columns = []
        for row in range(self.crm_mapping_table.rowCount()):
            src_item = self.crm_mapping_table.item(row, 0)
            target_item = self.crm_mapping_table.item(row, 1)
            if src_item and target_item:
                src_field = src_item.text().strip()
                target_field = target_item.text().strip()
                if src_field and target_field:
                    field_mapping[src_field] = target_field
                    format_widget = self.crm_mapping_table.cellWidget(row, 2)
                    format_value = ""
                    if format_widget:
                        format_value = format_widget.currentData() or ""
                    special_columns.append({"name": src_field, "format": str(format_value)})
        config = load_config()
        if 'business_rules' not in config:
            config['business_rules'] = {}
        config['business_rules']['crm_field_mapping'] = field_mapping
        config['business_rules']['crm_special_columns'] = special_columns
        save_config(config, immediate=True)
        self.apply_settings_immediately({'mapping', 'special_columns', 'crm'})

    def _on_batch_paste_file_gen_field_config(self):
        """批量粘贴文件生成字段配置（源字段 + 目标字段 + 字段格式）"""
        from PyQt6.QtWidgets import QDialog, QVBoxLayout, QLabel, QDialogButtonBox, QTextEdit, QMessageBox, QComboBox
        from PyQt6.QtGui import QFont
        from PyQt6.QtCore import QEvent, QObject
        if not hasattr(self, 'mapping_table'):
            frameless_message_box(self, "提示", "字段配置表格未初始化")
            return
        dialog = QDialog(self)
        dialog.setWindowTitle("批量粘贴")
        dialog.setMinimumSize(700, 400)
        dialog.setWindowFlags(dialog.windowFlags() | Qt.WindowType.FramelessWindowHint)
        layout = QVBoxLayout(dialog)
        layout.addWidget(QLabel("从Excel复制数据直接粘贴。支持Tab/逗号/空格分隔。\n格式：源字段\t目标字段\t字段格式（可选）"))
        text_edit = QTextEdit()
        text_edit.setFont(QFont("Consolas", 10))
        text_edit.setPlaceholderText("从Excel复制数据直接粘贴。")
        text_edit.setAcceptRichText(False)
        layout.addWidget(text_edit)
        buttons = QDialogButtonBox(QDialogButtonBox.StandardButton.Ok | QDialogButtonBox.StandardButton.Cancel)
        buttons.accepted.connect(dialog.accept)
        buttons.rejected.connect(dialog.reject)
        layout.addWidget(buttons)
        if not dialog.exec():
            return
        text = text_edit.toPlainText().strip()
        if not text:
            return

        format_name_to_data = {
            "文本": "{}", "日期 (YYYY-MM-DD)": "%Y-%m-%d",
            "日期 (YYYY年MM月DD日)": "%Y年%m月%d日",
            "人民币": "￥{:,.2f}", "金额": "{:,.2f}",
            "数字": "{:,.2f}", "整数": "{:,.0f}"
        }
        format_data_to_name = {v: k for k, v in format_name_to_data.items()}

        class WheelEventFilter(QObject):
            def eventFilter(self, obj, event):
                if event.type() == QEvent.Wheel:
                    return True
                return False

        table = self.mapping_table
        added = 0
        updated = 0
        existing = {}
        for r in range(table.rowCount()):
            item = table.item(r, 0)
            if item:
                existing[item.text().strip()] = r

        self._suspend_mapping_save = True
        table.blockSignals(True)
        for line in text.splitlines():
            line = line.strip()
            if not line:
                continue
            candidates = []
            if '\t' in line:
                candidates.append([p.strip() for p in line.split('\t')])
            if ',' in line and line.count(',') >= 2:
                candidates.append([p.strip() for p in line.split(',')])
            candidates.append([p.strip() for p in line.split(None, 2)])
            parts = max(candidates, key=len) if candidates else []
            if not parts or not parts[0]:
                continue
            src = parts[0]
            tgt = parts[1] if len(parts) > 1 else src
            fmt = parts[2] if len(parts) > 2 else ""
            # 支持格式名或格式字符串
            fmt_data = format_name_to_data.get(fmt, fmt) if fmt else ""
            if fmt_data not in format_name_to_data.values() and fmt_data != "":
                fmt_data = ""

            if src in existing:
                r = existing[src]
                table.setItem(r, 0, QTableWidgetItem(src))
                table.setItem(r, 1, QTableWidgetItem(tgt))
                # 更新格式下拉框
                fmt_combo = table.cellWidget(r, 2)
                if fmt_combo and isinstance(fmt_combo, QComboBox):
                    for j in range(fmt_combo.count()):
                        if fmt_combo.itemData(j) == fmt_data:
                            fmt_combo.setCurrentIndex(j)
                            break
                updated += 1
            else:
                r = table.rowCount()
                table.insertRow(r)
                table.setItem(r, 0, QTableWidgetItem(src))
                table.setItem(r, 1, QTableWidgetItem(tgt))
                fmt_combo = QComboBox()
                fmt_combo.addItem("", "")
                for fn, ff in format_name_to_data.items():
                    fmt_combo.addItem(fn, ff)
                if fmt_data:
                    for j in range(fmt_combo.count()):
                        if fmt_combo.itemData(j) == fmt_data:
                            fmt_combo.setCurrentIndex(j)
                            break
                wheel_filter = WheelEventFilter()
                if not hasattr(self, 'mapping_table_wheel_filters'):
                    self.mapping_table_wheel_filters = []
                self.mapping_table_wheel_filters.append(wheel_filter)
                fmt_combo.installEventFilter(wheel_filter)
                fmt_combo.currentIndexChanged.connect(lambda idx: self.on_save_mappings())
                table.setCellWidget(r, 2, fmt_combo)
                existing[src] = r
                added += 1

        table.blockSignals(False)
        self._suspend_mapping_save = False
        self.on_save_mappings(immediate=True)
        print(f"[文件生成字段配置批量粘贴] 新增: {added}, 更新: {updated}")

