        top_row.setSpacing(12)
        top_row.addWidget(product_group, 1)

        # ===== 右侧：Word模板选择（独立模板路径） =====
        template_group = QGroupBox("模板选择")
        template_layout = QVBoxLayout(template_group)
        template_layout.setSpacing(8)

        # 模板文件夹路径（独立于通用模板路径）
        bid_template_dir = self.config.get('path_config', {}).get('bid_template_dir', '')
        if not bid_template_dir:
            bid_template_dir = self.config.get('path_config', {}).get('template_dir', 'template')
        bid_dir_frame = QFrame()
        bid_dir_layout = QHBoxLayout(bid_dir_frame)
        bid_dir_layout.setContentsMargins(0, 0, 0, 0)
        bid_dir_label = QLabel("模板文件夹:")
        bid_dir_label.setFixedWidth(70)
        bid_dir_layout.addWidget(bid_dir_label)
        self.bid_template_dir_text = QLineEdit(bid_template_dir)
        self.bid_template_dir_text.setPlaceholderText("招标Word模板存放目录")
        bid_dir_layout.addWidget(self.bid_template_dir_text)
        bid_browse_btn = QPushButton("浏览")
        bid_browse_btn.setFixedWidth(60)
        bid_browse_btn.clicked.connect(lambda: self._on_browse_bid_template_dir())
        bid_dir_layout.addWidget(bid_browse_btn)
        self.bid_template_dir_text.textChanged.connect(lambda t: self._on_bid_template_dir_changed(t))
        template_layout.addWidget(bid_dir_frame)

        class _BidWheelFilter(QObject):
            def eventFilter(self, obj, event):
                if event.type() == QEvent.Wheel:
                    return True
                return False

        word_templates = self.config.get('pdf_watermark', {}).get('word_templates', {})
        default_bid_template = self.config.get('app_settings', {}).get('default_bid_template', '')

        self.bid_template_table = QTableWidget(len(word_templates), 3)
        self.bid_template_table.setHorizontalHeaderLabels(["默认", "模板名称", "模板路径"])
        self.bid_template_table_wheel_filters = []
        self.bid_default_template_checkboxes = []

        def _populate_bid_combos():
            """重新加载模板下拉框选项"""
            cur_dir = self.bid_template_dir_text.text().strip()
            dir_path = resolve_app_path(cur_dir) if cur_dir else None
            for row in range(self.bid_template_table.rowCount()):
                combo = self.bid_template_table.cellWidget(row, 2)
                if not combo:
                    continue
                cur_text = combo.currentText()
                combo.blockSignals(True)
                combo.clear()
                if dir_path and dir_path.exists() and dir_path.is_dir():
                    for word_file in dir_path.glob('*.docx'):
                        combo.addItem(str(word_file.relative_to(dir_path)))
                combo.setCurrentText(cur_text)
                combo.blockSignals(False)

        for i, (name, path) in enumerate(word_templates.items()):
            # 默认复选框
            checkbox = QCheckBox()
            checkbox.setChecked(name == default_bid_template)
            checkbox.stateChanged.connect(lambda state, row=i: self._on_bid_default_template_changed(row, state))
            self.bid_template_table.setCellWidget(i, 0, checkbox)
            self.bid_default_template_checkboxes.append(checkbox)

            name_item = QTableWidgetItem(name)
            self.bid_template_table.setItem(i, 1, name_item)

            combo = QComboBox()
            dir_path = resolve_app_path(bid_template_dir)
            if dir_path.exists() and dir_path.is_dir():
                for word_file in dir_path.glob('*.docx'):
                    combo.addItem(str(word_file.relative_to(dir_path)))
            combo.setCurrentText(path)
            combo.currentTextChanged.connect(lambda text, row=i: self._on_bid_template_path_changed(row, text))

            wf = _BidWheelFilter()
            self.bid_template_table_wheel_filters.append(wf)
            combo.installEventFilter(wf)
            self.bid_template_table.setCellWidget(i, 2, combo)

