        tpl_btn_layout.setAlignment(Qt.AlignCenter)
        tpl_add_btn = QPushButton("添加")
        tpl_add_btn.clicked.connect(lambda: self._on_bid_add_template(_populate_bid_combos))
        tpl_btn_layout.addWidget(tpl_add_btn)
        tpl_btn_layout.addSpacing(10)
        tpl_del_btn = QPushButton("删除")
        tpl_del_btn.clicked.connect(self._on_bid_delete_template)
        tpl_btn_layout.addWidget(tpl_del_btn)
        template_layout.addWidget(tpl_btn_frame)

        top_row.addWidget(template_group, 1)
        # opp_field_group 将在后面创建后加入 top_row，三者水平并排
        tab_layout.addLayout(top_row, 1)

        # ===== 第三行：字段映射列表 + 招投标映射值 =====
        combined_opp_tables_row = QHBoxLayout()
        combined_opp_tables_row.setSpacing(12)

        # ===== 左侧：字段映射列表（两列：显示名称 + API名称） =====
        opp_field_mapping_group = self._shared_groupbox("字段映射列表")
        opp_field_mapping_layout = QVBoxLayout(opp_field_mapping_group)
        opp_field_mapping_layout.setSpacing(8)

        from PyQt6.QtWidgets import QSizePolicy

        self.opp_field_mapping_list_table = QTableWidget()
        self.opp_field_mapping_list_table.setColumnCount(2)
        self.opp_field_mapping_list_table.setHorizontalHeaderLabels(["显示名称", "API名称"])
        install_autofilter_header(self.opp_field_mapping_list_table)
        self.opp_field_mapping_list_table.verticalHeader().setVisible(False)
        self.opp_field_mapping_list_table.setAlternatingRowColors(True)
        self.opp_field_mapping_list_table.setSelectionBehavior(QAbstractItemView.SelectionBehavior.SelectRows)
        self.opp_field_mapping_list_table.setSelectionMode(QAbstractItemView.SelectionMode.ExtendedSelection)
        self.opp_field_mapping_list_table.setEditTriggers(
            QAbstractItemView.EditTrigger.DoubleClicked |
            QAbstractItemView.EditTrigger.EditKeyPressed |
            QAbstractItemView.EditTrigger.AnyKeyPressed
        )
        self.opp_field_mapping_list_table.setSizePolicy(
            QSizePolicy.Policy.Expanding,
            QSizePolicy.Policy.Expanding
        )

        opp_header = self.opp_field_mapping_list_table.horizontalHeader()
        opp_header.setSectionResizeMode(0, QHeaderView.ResizeMode.Interactive)
        opp_header.setSectionResizeMode(1, QHeaderView.ResizeMode.Interactive)
        # ✅ 初始化期间阻塞信号，防止 setColumnWidth 触发 sectionResized
        #    将默认值覆盖掉用户之前调整的宽度
        opp_header.blockSignals(True)
        self.opp_field_mapping_list_table.setColumnWidth(0, 160)
        self.opp_field_mapping_list_table.setColumnWidth(1, 130)
        # ✅ 恢复已保存的列宽
        runtime_column_widths_opp = self.runtime_state.get('table_column_widths', {})
        saved_widths_opp = runtime_column_widths_opp.get('opp_field_mapping_list_table') or self.config.get('app_settings', {}).get('column_widths', {}).get('opp_field_mapping_list_table')
        if saved_widths_opp and len(saved_widths_opp) >= 2:
            self.opp_field_mapping_list_table.setColumnWidth(0, max(saved_widths_opp[0], 60) if saved_widths_opp[0] else 160)
            self.opp_field_mapping_list_table.setColumnWidth(1, max(saved_widths_opp[1], 60) if saved_widths_opp[1] else 130)
        opp_header.blockSignals(False)
        opp_header.sectionResized.connect(lambda logicalIndex, oldSize, newSize: self.save_column_widths('opp_field_mapping_list_table'))

        # 从配置加载已保存的商机字段映射列表
        saved_opp_mappings = config.get('opportunity', {}).get('field_mapping_list', [])
        unique_mappings = {}
        for mapping in saved_opp_mappings:
            if isinstance(mapping, dict):
                api_name = mapping.get('api_name', '')
                if api_name:
                    unique_mappings[api_name] = mapping
        deduplicated_opp_mappings = list(unique_mappings.values())

        self.opp_field_mapping_list_table.setRowCount(max(len(deduplicated_opp_mappings), 1))
        for row, mapping in enumerate(deduplicated_opp_mappings):
            if isinstance(mapping, dict):
                api_name = mapping.get('api_name', '')
                display_name = mapping.get('display_name', '')
                self.opp_field_mapping_list_table.setItem(row, 0, QTableWidgetItem(display_name))
                self.opp_field_mapping_list_table.setItem(row, 1, QTableWidgetItem(api_name))

