    def on_add_product(self):
        """添加产品"""
        row_position = self.product_table.rowCount()
        self.product_table.insertRow(row_position)
        self.product_table.setItem(row_position, 0, QTableWidgetItem("新产品"))
        
        # 为PDF文件夹路径列创建包含文本框和浏览按钮的单元格
        cell_widget = QFrame()
        cell_layout = QHBoxLayout(cell_widget)
        cell_layout.setContentsMargins(0, 0, 0, 0)
        
        # 添加文本框
        folder_edit = QLineEdit("")
        folder_edit.setObjectName(f"folder_edit_{row_position}")
        folder_edit.textChanged.connect(lambda t, row=row_position: self._on_product_folder_changed(row))
        cell_layout.addWidget(folder_edit)
        
        # 添加浏览按钮
        browse_btn = QPushButton("浏览")
        browse_btn.setFixedWidth(60)
        browse_btn.clicked.connect(lambda checked, row=row_position: self.on_browse_product_folder(row))
        cell_layout.addWidget(browse_btn)
        
        # 设置单元格小部件
        self.product_table.setCellWidget(row_position, 1, cell_widget)
        
        # 自动选中新添加的行
        self.product_table.selectRow(row_position)
        # 开始编辑产品名称
        self.product_table.editItem(self.product_table.item(row_position, 0))

    def on_delete_product(self):
        """删除产品"""
        selected_row = self.product_table.currentRow()
        if selected_row >= 0:
            self.product_table.removeRow(selected_row)
            # 保存修改
            self.on_save_products()
        else:
            # 如果没有选择行，删除最后一行
            if self.product_table.rowCount() > 0:
                self.product_table.removeRow(self.product_table.rowCount() - 1)
                # 保存修改
                self.on_save_products()

    def on_browse_product_folder(self, row=None):
        """浏览产品PDF文件夹"""
        if row is None:
            row = self.product_table.currentRow()
        if row >= 0:
            from PyQt6.QtWidgets import QFileDialog
            
            # 获取当前文本框的内容作为初始路径
            current_path = ""
            cell_widget = self.product_table.cellWidget(row, 1)
            if cell_widget:
                for child in cell_widget.children():
                    if isinstance(child, QLineEdit):
                        current_path = child.text().strip()
                        break
            
            if not current_path or not os.path.exists(current_path):
                current_path = ""
                
            dir_path = QFileDialog.getExistingDirectory(self, "选择PDF文件夹", current_path)
            if dir_path:
                # 获取单元格小部件
                if cell_widget:
                    # 查找文本框
                    for child in cell_widget.children():
                        if isinstance(child, QLineEdit):
                            child.setText(dir_path)
                            # 保存修改
                            self.on_save_products()
                            break

    def _on_product_folder_changed(self, row):
        """预设文件夹路径变更时保存"""
        if hasattr(self, '_loading_product_table'):
            return
        self.on_save_products()

    def on_save_products(self):
        """保存产品列表"""
        try:
            product_models = []
            product_folders = {}
            
            for row in range(self.product_table.rowCount()):
                product_item = self.product_table.item(row, 0)
                
                if product_item and product_item.text().strip():
                    product = product_item.text().strip()
                    product_models.append(product)
                    
                    # 从单元格小部件中获取PDF文件夹路径
                    cell_widget = self.product_table.cellWidget(row, 1)
                    if cell_widget:
                        # 查找文本框
                        for child in cell_widget.children():
                            if isinstance(child, QLineEdit):
                                product_folders[product] = child.text().strip()
                                break
            
            # 保存到配置
            config = load_config()
            if 'pdf_watermark' not in config:
                config['pdf_watermark'] = {}
            config['pdf_watermark']['product_models'] = product_models
            config['pdf_watermark']['product_folders'] = product_folders
            save_config(config, immediate=True)
            self.apply_settings_immediately({'product'})

            # 通知主界面更新产品型号下拉框
            if 'MainFrame' in globals() and hasattr(globals()['MainFrame'], 'instance') and globals()['MainFrame'].instance:
                main_frame = globals()['MainFrame'].instance
                if hasattr(main_frame, 'update_product_models'):
                    main_frame.update_product_models()
        except Exception as e:
            logging.error(f"保存产品列表失败: {str(e)}")

    # ===== 招标设置 - 模板选择 =====
    def _on_browse_bid_template_dir(self):
        """浏览招标模板文件夹"""
        cur = self.bid_template_dir_text.text().strip()
        if cur and os.path.exists(cur):
            start_dir = cur
        else:
            start_dir = str(resolve_app_path('template'))
        path = QFileDialog.getExistingDirectory(self, "选择招标模板文件夹", start_dir)
        if path:
            self.bid_template_dir_text.setText(path)

    def _on_bid_template_dir_changed(self, text):
        """招标模板文件夹路径变更时保存并刷新下拉选项"""
        config = load_config()
        if 'path_config' not in config:
            config['path_config'] = {}
        config['path_config']['bid_template_dir'] = text.strip()
        save_config(config, immediate=True)
        # 刷新表格中所有下拉框的选项
        dir_path = resolve_app_path(text.strip()) if text.strip() else None
        for row in range(self.bid_template_table.rowCount()):
            combo = self.bid_template_table.cellWidget(row, 2)
            if not combo:
                continue
            cur_text = combo.currentText()
            combo.blockSignals(True)
            combo.clear()
            if dir_path and dir_path.exists() and dir_path.is_dir():
                for word_file in dir_path.glob('*.docx'):
                    combo.addItem(str(word_file.relative_to(dir_path)))
            combo.setCurrentText(cur_text)
            combo.blockSignals(False)

    def _on_bid_template_path_changed(self, row, text):
        """招标模板路径变更时保存"""
        self._on_save_bid_templates()

    def _on_save_bid_templates(self):
        """保存招标Word模板配置"""
        try:
            templates = {}
            for row in range(self.bid_template_table.rowCount()):
                name_item = self.bid_template_table.item(row, 1)
                combo = self.bid_template_table.cellWidget(row, 2)
                if name_item and combo:
                    name = name_item.text().strip()
                    path = combo.currentText().strip()
                    if name:
                        templates[name] = path
            config = load_config()
            if 'pdf_watermark' not in config:
                config['pdf_watermark'] = {}
            config['pdf_watermark']['word_templates'] = templates
            if hasattr(self, 'bid_template_dir_text'):
                if 'path_config' not in config:
                    config['path_config'] = {}
                config['path_config']['bid_template_dir'] = self.bid_template_dir_text.text().strip()
            save_config(config, immediate=True)
            self.config = config
            self.apply_settings_immediately({'template', 'opportunity'})
        except Exception as e:
            logging.error(f"保存招标模板失败: {str(e)}")

    def _on_bid_default_template_changed(self, row, state):
        """招标默认模板复选框 - 单选逻辑"""
        from PyQt6.QtCore import Qt
        if state == Qt.CheckState.Checked.value:
            for i, cb in enumerate(getattr(self, 'bid_default_template_checkboxes', [])):
                if i != row:
                    cb.blockSignals(True)
                    cb.setChecked(False)
                    cb.blockSignals(False)
            self._save_default_bid_template(row)

    def _save_default_bid_template(self, row):
        """保存默认招标模板"""
        try:
            name_item = self.bid_template_table.item(row, 1)
            if name_item:
                template_name = name_item.text().strip()
                config = load_config()
                if 'app_settings' not in config:
                    config['app_settings'] = {}
                config['app_settings']['default_bid_template'] = template_name
                save_config(config, immediate=True)
                self.config = config
                self.apply_settings_immediately({'template', 'opportunity'})
        except Exception as e:
            logging.error(f"保存默认招标模板失败: {str(e)}")

    def _on_bid_add_template(self, populate_func=None):
        """添加招标模板行"""
        row = self.bid_template_table.rowCount()
        self.bid_template_table.insertRow(row)
        # 默认复选框
        checkbox = QCheckBox()
        checkbox.stateChanged.connect(lambda state, r=row: self._on_bid_default_template_changed(r, state))
        self.bid_template_table.setCellWidget(row, 0, checkbox)
        self.bid_default_template_checkboxes.append(checkbox)
        name_item = QTableWidgetItem("新模板")
        self.bid_template_table.setItem(row, 1, name_item)
        combo = QComboBox()
        cur_dir = self.bid_template_dir_text.text().strip() if hasattr(self, 'bid_template_dir_text') else ''
        if not cur_dir:
            cur_dir = self.config.get('path_config', {}).get('template_dir', 'template')
        dir_path = resolve_app_path(cur_dir) if cur_dir else None
        if dir_path and dir_path.exists() and dir_path.is_dir():
            for word_file in dir_path.glob('*.docx'):
                combo.addItem(str(word_file.relative_to(dir_path)))
        combo.currentTextChanged.connect(lambda text, r=row: self._on_bid_template_path_changed(r, text))
        from PyQt6.QtCore import QEvent, QObject
        class _Wf(QObject):
            def eventFilter(self, obj, event):
                return event.type() == QEvent.Wheel
        wf = _Wf()
        self.bid_template_table_wheel_filters.append(wf)
        combo.installEventFilter(wf)
        self.bid_template_table.setCellWidget(row, 2, combo)
        self._on_save_bid_templates()

    def _on_bid_delete_template(self):
        """删除招标模板行"""
        current_row = self.bid_template_table.currentRow()
        if current_row < 0:
            current_row = max(0, self.bid_template_table.rowCount() - 1)
        if self.bid_template_table.rowCount() > 0:
            self.bid_template_table.removeRow(current_row)
            if hasattr(self, 'bid_default_template_checkboxes') and current_row < len(self.bid_default_template_checkboxes):
                del self.bid_default_template_checkboxes[current_row]
        self._on_save_bid_templates()

