    def on_direct_login(self):
        """直接登录"""
        # 获取选中的行
        selected_indexes = self.user_list.selectionModel().selectedRows()
        if not selected_indexes:
            show_info("提示", "请先选择要登录的用户")
            return
        
        # 获取选中的用户
        row = selected_indexes[0].row()
        user = self.user_model.users[row]
        username = user.get('username')
        
        # 弹窗提示是否登录
        if ask_yes_no("确认登录", f"确定要登录用户 {username} 吗？"):
            # 更新全局变量
            global current_user, user_type
            current_user = username
            user_type = "member"
            save_user_cache(username, "member")
            
            # 显示成功信息并重启程序
            # 创建一个自动关闭的弹窗
            class AutoCloseMessageBox(CenteredPopupDialog):
                """支持自动关闭的消息框。"""
                def __init__(self, title, message, parent=None):
                    """初始化自动关闭消息框。"""
                    super().__init__(parent, center_reference=parent)
                    self.setWindowTitle(title)
                    self.resize(300, 150)
                    
                    # 设置主题
                    set_dialog_opacity(self)
                    
                    layout = QVBoxLayout()
                    self.label = QLabel(message)
                    self.label.setAlignment(Qt.AlignCenter)
                    layout.addWidget(self.label)
                    self.setLayout(layout)
                    
                    # 2秒后自动关闭
                    self.timer = QTimer(self)
                    self.timer.timeout.connect(self.close)
                    self.timer.start(2000)
            
            # 显示自动关闭的弹窗
            msg_box = AutoCloseMessageBox("成功", "用户切换成功，程序将重启")
            msg_box.exec()
            
            import time
            time.sleep(1)
            # 重启程序
            os.execl(sys.executable, sys.executable, *sys.argv)

    def wheelEvent(self, event):
        """鼠标滚轮事件处理，用于调整滑块值"""
        # 检查鼠标是否在透明度滑块上
        if hasattr(self, 'opacity_slider') and self.opacity_slider.underMouse():
            delta = event.angleDelta().y()
            if delta > 0:
                # 向上滚动，增加值
                new_value = min(self.opacity_slider.maximum(), self.opacity_slider.value() + 5)
                self.opacity_slider.setValue(new_value)
            else:
                # 向下滚动，减少值
                new_value = max(self.opacity_slider.minimum(), self.opacity_slider.value() - 5)
                self.opacity_slider.setValue(new_value)
        
        # 检查鼠标是否在宽度滑块上
        if hasattr(self, 'output_width_slider') and self.output_width_slider.underMouse():
            delta = event.angleDelta().y()
            if delta > 0:
                # 向上滚动，增加值
                new_value = min(self.output_width_slider.maximum(), self.output_width_slider.value() + 20)
                self.output_width_slider.setValue(new_value)
            else:
                # 向下滚动，减少值
                new_value = max(self.output_width_slider.minimum(), self.output_width_slider.value() - 20)
                self.output_width_slider.setValue(new_value)
        
        # 检查鼠标是否在高度滑块上
        if hasattr(self, 'output_height_slider') and self.output_height_slider.underMouse():
            delta = event.angleDelta().y()
            if delta > 0:
                # 向上滚动，增加值
                new_value = min(self.output_height_slider.maximum(), self.output_height_slider.value() + 1)
                self.output_height_slider.setValue(new_value)
            else:
                # 向下滚动，减少值
                new_value = max(self.output_height_slider.minimum(), self.output_height_slider.value() - 1)
                self.output_height_slider.setValue(new_value)
    
    def resizeEvent(self, event):
        """设置窗口大小改变事件处理"""
        # 实时保存窗口大小
        config = load_config()
        if 'app_settings' not in config:
            config['app_settings'] = {}
        new_size = [self.width(), self.height()]
        config['app_settings']['settings_window_size'] = new_size
        save_user_runtime_state({'settings_window_size': new_size}, immediate=True, merge=True)
        save_config(config)
        
        super().resizeEvent(event)
    
    def on_tab_moved(self, from_index, to_index):
        """选项卡移动事件处理，保存选项卡位置"""
        # 获取当前选项卡顺序
        tab_order = []
        for i in range(self.notebook.count()):
            tab_order.append(self.notebook.tabText(i))
        
        # 保存到配置
        config = load_config()
        if 'app_settings' not in config:
            config['app_settings'] = {}
        config['app_settings']['tab_order'] = tab_order
        save_user_runtime_state({'settings_tab_order': tab_order}, immediate=True, merge=True)
        save_config(config)
    
    def restore_tab_order(self):
        """恢复选项卡位置"""
        # 从配置中加载选项卡顺序
        config = load_config()
        runtime_state = load_user_runtime_state()
        tab_order = runtime_state.get('settings_tab_order') or config.get('app_settings', {}).get('tab_order', [])
        
        if tab_order:
            # 按保存的顺序重新排列选项卡
            for i, tab_name in enumerate(tab_order):
                for j in range(self.notebook.count()):
                    if self.notebook.tabText(j) == tab_name:
                        if i != j:
                            # 移动选项卡到正确的位置
                            self.notebook.tabBar().moveTab(j, i)
                        break
    
    def load_user_data_and_create_tabs(self):
        """在后台线程中加载用户数据并创建依赖用户数据的标签页"""
        try:
            # 加载用户数据
            self.users_data = load_users()
            
            # 获取用户权限
            global current_user, user_type
            if current_user:
                users = self.users_data.get('users', [])
                for user in users:
                    if user.get('username') == current_user:
                        # 为新用户和管理员添加的用户设置默认权限
                        # 所有用户默认都有通用设置、路径、字段格式、字段映射、模板、产品列表管理权限
                        self.user_permissions = user.get('permissions', {
                            "path": True,
                            "field_format": True,
                            "field_mapping": True,
                            "template": True,
                            "product_list": True,
                            "feature_selection": True,
                            "database_config": False
                        })
                        break
            
            # 使用信号槽在主线程中创建标签页
            from PyQt6.QtCore import QTimer
            QTimer.singleShot(0, self.create_user_dependent_tabs)
        except Exception as e:
            logging.error(f"加载用户数据失败: {str(e)}")
    
    def create_user_dependent_tabs(self):
        """创建依赖用户数据的标签页"""
        global current_user, user_type
        
        # 检查是否为管理员
        is_admin_user = False
        if user_type == "admin":
            is_admin_user = True
        elif current_user:
            # 也可以通过用户名直接判断是否为管理员
            if current_user == "Zengjiataoadmin" or current_user == "001":
                is_admin_user = True
        
        # 如果是管理员，添加用户管理（含密码管理）和MySQL配置
        if is_admin_user:
            self.create_user_management_tab()  # 用户管理
            self.create_mysql_config_tab()  # MySQL配置
            self.create_api_config_tab()    # API 配置
        else:
            # 普通用户显示个人账号界面
            self.create_profile_tab()
        
        # 重新恢复选项卡位置，确保新添加的标签页也能正确排序
        self.restore_tab_order()

