        header.setSectionResizeMode(0, QHeaderView.ResizeMode.Interactive)
        header.setSectionResizeMode(1, QHeaderView.ResizeMode.Interactive)
        # ✅ 初始化期间阻塞信号，防止 setColumnWidth 触发 sectionResized
        #    将默认值保存到配置文件，覆盖掉用户之前调整的宽度
        header.blockSignals(True)
        self.crm_field_mapping_list_table.setColumnWidth(0, 160)
        self.crm_field_mapping_list_table.setColumnWidth(1, 130)
        # ✅ 恢复已保存的列宽
        rts_path = get_user_runtime_state_path()
        runtime_column_widths = self.runtime_state.get('table_column_widths', {})
        rt_saved = runtime_column_widths.get('crm_field_mapping_list_table')
        cfg_saved = self.config.get('app_settings', {}).get('column_widths', {}).get('crm_field_mapping_list_table')
        saved_widths = rt_saved or cfg_saved
        print(f"[列宽恢复] 📖 crm_field_mapping_list_table | 文件={rts_path} | runtime={rt_saved} | config={cfg_saved} | 最终={saved_widths}")
        if saved_widths and len(saved_widths) >= 2:
            w0 = max(saved_widths[0], 60) if saved_widths[0] else 160
            w1 = max(saved_widths[1], 60) if saved_widths[1] else 130
            print(f"[列宽恢复] ✅ 设置为: [{w0}, {w1}]")
            self.crm_field_mapping_list_table.setColumnWidth(0, w0)
            self.crm_field_mapping_list_table.setColumnWidth(1, w1)
        else:
            print(f"[列宽恢复] ⚠️ 无已保存数据，使用默认 [160, 130]")
        header.blockSignals(False)
        header.sectionResized.connect(lambda logicalIndex, oldSize, newSize: self.save_column_widths('crm_field_mapping_list_table'))

        saved_field_mappings = fx_cfg.get('crm_field_mapping_list', [])

        # ✅【2026-05-11 修复】加载时进行去重，防止重复数据显示
        unique_mappings = {}
        for mapping in saved_field_mappings:
            if isinstance(mapping, dict):
                api_name = mapping.get('api_name', mapping.get('original_field', ''))
                if api_name:
                    # 以api_name为键自动去重（后面的覆盖前面的）
                    unique_mappings[api_name] = mapping

        # 转换为列表并设置行数
        deduplicated_mappings = list(unique_mappings.values())
        self.crm_field_mapping_list_table.setRowCount(max(len(deduplicated_mappings), 1))

        for row, mapping in enumerate(deduplicated_mappings):
            if isinstance(mapping, dict):
                api_name = mapping.get('api_name', mapping.get('original_field', ''))
                display_name = mapping.get('display_name', mapping.get('label', ''))
                # ✅ 如果显示名称为空或等于API名称，尝试从已知字段定义中查找中文名
                if (not display_name or display_name == api_name) and api_name:
                    resolved = self._resolve_field_display_name(api_name)
                    if resolved:
                        display_name = resolved
                self.crm_field_mapping_list_table.setItem(row, 0, QTableWidgetItem(display_name))
                self.crm_field_mapping_list_table.setItem(row, 1, QTableWidgetItem(api_name))

        self.crm_field_mapping_list_table.itemChanged.connect(self._on_crm_field_mapping_list_changed)
        # ✅ 右键时先选中当前行，避免编辑跨行
        self.crm_field_mapping_list_table.setContextMenuPolicy(Qt.ContextMenuPolicy.CustomContextMenu)
        self.crm_field_mapping_list_table.customContextMenuRequested.connect(self._on_field_mapping_context_menu)
