        # ===== CRM字段映射（从原CRM字段标签页移动过来） =====
        field_mapping_section_group = self._shared_groupbox("CRM字段映射")
        field_mapping_section_layout = QVBoxLayout(field_mapping_section_group)

        crm_field_mapping_data = self.config.get('business_rules', {}).get('crm_field_mapping', {})
        crm_special_columns_data = self.config.get('business_rules', {}).get('crm_special_columns', [])

        if crm_special_columns_data and isinstance(crm_special_columns_data, list) and len(crm_special_columns_data) > 0:
            if isinstance(crm_special_columns_data[0], str):
                crm_special_columns_data = [{"name": col, "format": ""} for col in crm_special_columns_data]
        elif crm_special_columns_data and isinstance(crm_special_columns_data, dict):
            crm_special_columns_data = [{"name": k, "format": v} for k, v in crm_special_columns_data.items()]

        format_dict_data = {}
        if crm_special_columns_data:
            for col in crm_special_columns_data:
                if isinstance(col, dict):
                    format_dict_data[col['name']] = col.get('format', '')

        class _CrmMappingWheelFilter(QObject):
            def eventFilter(self, obj, event):
                if event.type() == QEvent.Wheel:
                    return True
                return False

        all_fields = set(crm_field_mapping_data.keys())
        if crm_special_columns_data:
            for col in crm_special_columns_data:
                if isinstance(col, dict):
                    all_fields.add(col['name'])

        self.crm_mapping_table = QTableWidget(len(all_fields), 3)
        self.crm_mapping_table.setHorizontalHeaderLabels(["源字段", "目标字段", "字段格式"])
        self.crm_mapping_table.setSelectionBehavior(QAbstractItemView.SelectionBehavior.SelectRows)
        self.crm_mapping_table.setSelectionMode(QAbstractItemView.SelectionMode.ExtendedSelection)

        self.crm_mapping_table_wheel_filters = []

        format_options = [
            {"name": "文本", "format": "{}"},
            {"name": "日期 (YYYY-MM-DD)", "format": "%Y-%m-%d"},
            {"name": "日期 (YYYY年MM月DD日)", "format": "%Y年%m月%d日"},
            {"name": "人民币", "format": "￥{:,.2f}"},
            {"name": "金额", "format": "{:,.2f}"},
            {"name": "数字", "format": "{:,.2f}"},
            {"name": "整数", "format": "{:,.0f}"}
        ]

        for i, field_name in enumerate(sorted(all_fields)):
            src_item = QTableWidgetItem(field_name)
            self.crm_mapping_table.setItem(i, 0, src_item)

            target_value = crm_field_mapping_data.get(field_name, field_name)
            target_item = QTableWidgetItem(target_value)
            self.crm_mapping_table.setItem(i, 1, target_item)

            format_combo_fm = QComboBox()
            format_combo_fm.addItem("", "")
            for opt in format_options:
                format_combo_fm.addItem(opt["name"], opt["format"])

            current_format = format_dict_data.get(field_name, "")
            if current_format:
                for j in range(format_combo_fm.count()):
                    if format_combo_fm.itemData(j) == current_format:
                        format_combo_fm.setCurrentIndex(j)
                        break

            wheel_filter_fm = _CrmMappingWheelFilter()
            self.crm_mapping_table_wheel_filters.append(wheel_filter_fm)
            format_combo_fm.installEventFilter(wheel_filter_fm)
            format_combo_fm.currentIndexChanged.connect(lambda index: self.on_save_crm_mappings())

            self.crm_mapping_table.setCellWidget(i, 2, format_combo_fm)

        self.crm_mapping_table.horizontalHeader().setSectionResizeMode(QHeaderView.Interactive)
