        # ===== CRM模板管理（从原CRM模板标签页移动过来） =====
        template_section_group = QGroupBox("CRM模板管理")
        template_section_layout = QVBoxLayout(template_section_group)

        crm_word_templates_data = self.config.get('file_config', {}).get('crm_word_templates', {})
        crm_template_target_paths_data = self.config.get('path_config', {}).get('crm_template_target_paths', {})
        crm_template_dir_data = self.config.get('path_config', {}).get('crm_template_dir', 'template')
        default_crm_template_data = self.config.get('app_settings', {}).get('default_crm_template', '')

        self.create_path_entry(template_section_layout, "CRM模板文件夹:", crm_template_dir_data, "crm_template_dir", is_dir=True)

