            combo_tmpl.currentTextChanged.connect(lambda text, row=i: self.on_crm_template_path_changed(row, text))

            wheel_filter_tmpl = _CrmTemplateWheelFilter()
            self.crm_template_table_wheel_filters.append(wheel_filter_tmpl)
            combo_tmpl.installEventFilter(wheel_filter_tmpl)

            self.crm_template_table.setCellWidget(i, 2, combo_tmpl)

            target_path_tmpl = str(crm_template_target_paths_data.get(name, '') or '').strip()
